1	//! Multi-publisher output dedup primitives.
2	//!
3	//! When several independent publishers mirror the same feed, the bridge demultiplexes them by
4	//! source IP (so each publisher's frame-sequence state stays separate — see `receiver`/`processor`)
5	//! but deduplicates the *output*, so a subscriber sees a clean stream regardless of which publisher
6	//! delivered a given update first. These primitives are keyed on business identity and therefore
7	//! operate on the merged stream — they need no per-publisher demux themselves.
8	//!
9	//! Two primitives, by message semantics:
10	//! - quotes ([`StalenessFloor`]): a full-state BBO is a *snapshot*, but two distinct BBOs can share
11	//!   a `source_ts` (the venue stamps coarsely — block-granular — while the book changes faster), so
12	//!   one `source_ts` "tick" holds a whole sub-sequence of real top-of-book changes. The catch: the
13	//!   only trustworthy ordering of those changes is a *single* publisher's own stream. Arrival order
14	//!   across publishers is corrupted by per-publisher network delay (the `hl-bbo-feed-race` board
15	//!   shows inter-feed skew over 100 ms), so interleaving two sources inside one tick can serve a
16	//!   stale sample as the freshest — on a falling price, a slower publisher's older, higher sample
17	//!   landing last reads as a phantom uptick. So the floor **latches to the leader**: per `(venue,
18	//!   symbol)` tick it emits only the *leader* (first publisher to open the tick — the lowest-delay
19	//!   source for it) and drops other publishers' samples at that `source_ts`; the leader is
20	//!   re-selected each new tick. Output `source_ts` is non-decreasing per key, and within each tick
21	//!   the emitted series is one publisher's coherent, in-order subsequence.
22	//! - trades ([`WindowedDedup`]): a trade is a *point-in-time event*, not state, so a floor would lose
23	//!   prints. It keeps the windowed `trade_id` identity instead: a competing publisher's copy or an
24	//!   in-window reorder is dropped, but every distinct print is kept.
25	
26	use std::{
27	    collections::{HashMap, HashSet, VecDeque},
28	    hash::Hash,
29	};
30	
31	/// Per-key **latch-to-leader** floor on `source_ts`. Tracks, per key, the highest `source_ts`
32	/// emitted, the *leader* publisher latched for that tick, and the set of distinct content the leader
33	/// has emitted at it. The `source_ts` never goes backwards, and within one tick only the leader is
34	/// emitted:
35	/// - `source_ts < high_water` → false (stale: a later tick already passed; any publisher).
36	/// - `source_ts > high_water` → advance the floor, latch the leader to this publisher, reset the
37	///   tick's content set, true.
38	/// - `source_ts == high_water` → false if `publisher != leader` (a non-leader sample at this tick:
39	///   its arrival order relative to the leader is delay-corrupted and untrustworthy, so it is
40	///   dropped); otherwise true iff the content is new at the tick (the leader's own exact
41	///   `(source_ts, content)` repeat is dropped).
42	///
43	/// The first sample for a key behaves as the `>` case (it opens the tick and becomes leader). Output
44	/// `source_ts` is non-decreasing per key; within a tick the emitted series is the leader's coherent,
45	/// in-order subsequence.
46	///
47	/// Memory is O(distinct leader content at the current tick) per key — bounded by how fast the book
48	/// moves within one `source_ts`; no fixed window needed.
49	pub struct StalenessFloor<K, V, P> {
50	    /// Per key: (high_water source_ts, leader publisher at that tick, leader's content set at it).
51	    state: HashMap<K, (u64, P, HashSet<V>)>,
52	}
53	
54	impl<K: Eq + Hash, V: Eq + Hash, P> Default for StalenessFloor<K, V, P> {
55	    fn default() -> Self {
56	        Self {
57	            state: HashMap::new(),
58	        }
59	    }
60	}
61	
62	impl<K: Eq + Hash, V: Eq + Hash, P: Eq> StalenessFloor<K, V, P> {
63	    pub fn new() -> Self {
64	        Self::default()
65	    }
66	
67	    /// True (recording it) iff this `(source_ts, content)` from `publisher` should be emitted under
68	    /// the latch-to-leader floor (see the type docs for the three cases).
69	    ///
70	    /// Records on the emit *decision*: in this gateway "emit" == handing the message to the broadcast
71	    /// channel, the only delivery step. A no-subscriber send desyncs no one, and a unique quote
72	    /// dropped by a slow per-client channel is unrecoverable regardless — so there is no failed-send
73	    /// path on which the floor must avoid advancing.
74	    pub fn admit(&mut self, key: K, source_ts: u64, content: V, publisher: P) -> bool {
75	        use std::collections::hash_map::Entry;
76	        match self.state.entry(key) {
77	            Entry::Vacant(v) => {
78	                let mut set = HashSet::new();
79	                set.insert(content);
80	                v.insert((source_ts, publisher, set));
81	                true
82	            }
83	            Entry::Occupied(mut o) => {
84	                let (high_water, leader, set) = o.get_mut();
85	                if source_ts < *high_water {
86	                    false
87	                } else if source_ts > *high_water {
88	                    *high_water = source_ts;
89	                    *leader = publisher;
90	                    set.clear();
91	                    set.insert(content);
92	                    true
93	                } else if publisher != *leader {
94	                    false
95	                } else {
96	                    set.insert(content)
97	                }
98	            }
99	        }
100	    }
101	}
102	
103	/// Per-key bounded dedup of recently-seen identities. Keeps the most recent `capacity` values per
104	/// key, so a duplicate from a second publisher (or a reorder within the window) is dropped while
105	/// memory stays bounded.
106	///
107	/// Window correctness depends on the `no_business_duplicates` oracle's assumption that each identity
108	/// is unique per `(venue, symbol)`: the window must exceed the worst-case number of distinct values
109	/// between competing publishers' copies of the same value, or a late duplicate re-emits.
110	pub struct WindowedDedup<K, V> {
111	    capacity: usize,
112	    seen: HashMap<K, (HashSet<V>, VecDeque<V>)>,
113	}
114	
115	impl<K: Eq + Hash + Clone, V: Eq + Hash + Copy> WindowedDedup<K, V> {
116	    pub fn new(capacity: usize) -> Self {
117	        Self {
118	            capacity,
119	            seen: HashMap::new(),
120	        }
121	    }
122	
123	    /// True if `value` has not been seen recently for `key` (recording it); false if it is a
124	    /// duplicate still inside the window.
125	    ///
126	    /// Records on the emit *decision*: in this gateway "emit" == handing the message to the
127	    /// broadcast channel, the only delivery step. A no-subscriber send desyncs no one, and a unique
128	    /// update dropped by a slow per-client channel is unrecoverable regardless — so there is no
129	    /// failed-send path on which the cache must avoid advancing.
130	    pub fn is_new(&mut self, key: K, value: V) -> bool {
131	        let (set, order) = self.seen.entry(key).or_default();
132	        if !set.insert(value) {
133	            return false;
134	        }
135	        order.push_back(value);
136	        if order.len() > self.capacity {
137	            if let Some(old) = order.pop_front() {
138	                set.remove(&old);
139	            }
140	        }
141	        true
142	    }
143	}
144	
145	#[cfg(test)]
146	mod tests {
147	    use super::*;
148	
149	    #[test]
150	    fn quote_first_sample_admits() {
151	        let mut f: StalenessFloor<&str, u8, u8> = StalenessFloor::new();
152	        assert!(f.admit("BTC", 1000, 0, 1)); // first for this key always emits (and latches leader)
153	    }
154	
155	    #[test]
156	    fn quote_new_tick_admits_and_relatches_leader() {
157	        let mut f: StalenessFloor<&str, u8, u8> = StalenessFloor::new();
158	        assert!(f.admit("BTC", 1000, 0, 1)); // pub 1 opens tick -> leader
159	        assert!(f.admit("BTC", 1001, 0, 2)); // newer tick re-latches to pub 2 (even identical content)
160	        assert!(f.admit("BTC", 2000, 0, 1)); // newer tick again, leader back to pub 1
161	    }
162	
163	    /// Latch-to-leader within one tick: the leader (first publisher to open the tick) emits its
164	    /// distinct contents in order; a *second* publisher's sample at the same `source_ts` is dropped
165	    /// even when its content is new. This is the false-uptick fix — on a falling price, admitting a
166	    /// slower publisher's older, higher sample as a "fresh" change would serve a stale value as the
167	    /// latest. Exact leader repeats are also dropped.
168	    #[test]
169	    fn quote_latches_to_leader_within_tick() {
170	        let (a, b) = (1u8, 2u8);
171	        let mut f: StalenessFloor<&str, u8, u8> = StalenessFloor::new();
172	        // Falling price within tick T; leader A observes 5, 4, 3 in its own (trustworthy) order:
173	        assert!(f.admit("BTC", 1000, 5, a)); // opens tick -> A is leader, emit 5
174	        assert!(!f.admit("BTC", 1000, 5, a)); // A's exact repeat dropped
175	        assert!(f.admit("BTC", 1000, 4, a)); // A's next distinct content kept
176	        assert!(f.admit("BTC", 1000, 3, a)); // A's next distinct content kept
177	                                             // B (higher delay) samples 39 at the same tick, arriving last. DROPPED even though A never
178	                                             // sent 39: its order relative to A is delay-corrupted, so emitting it risks a phantom tick.
179	        assert!(!f.admit("BTC", 1000, 39, b));
180	        // A new tick re-opens the latch; whichever publisher gets there first leads it.
181	        assert!(f.admit("BTC", 1001, 39, b)); // B opens the next tick -> B leads, emit
182	        assert!(!f.admit("BTC", 1001, 2, a)); // A is now the non-leader at this tick -> dropped
183	    }
184	
185	    #[test]
186	    fn quote_stale_tick_dropped_for_any_publisher() {
187	        let (a, b) = (1u8, 2u8);
188	        let mut f: StalenessFloor<&str, u8, u8> = StalenessFloor::new();
189	        assert!(f.admit("BTC", 2000, 1, a));
190	        assert!(!f.admit("BTC", 1999, 9, a)); // strictly older tick -> stale, dropped
191	        assert!(!f.admit("BTC", 1999, 9, b)); // and from the other publisher too
192	    }
193	
194	    #[test]
195	    fn quote_keys_are_independent() {
196	        let mut f: StalenessFloor<&str, u8, u8> = StalenessFloor::new();
197	        assert!(f.admit("BTC", 2000, 0, 1));
198	        assert!(f.admit("ETH", 1000, 0, 1)); // separate floor + leader per key
199	        assert!(!f.admit("BTC", 1500, 0, 1)); // BTC's floor unaffected by ETH
200	    }
201	
202	    #[test]
203	    fn trade_new_admitted_repeat_dropped() {
204	        let mut d: WindowedDedup<&str, u64> = WindowedDedup::new(8);
205	        assert!(d.is_new("BTC", 1));
206	        assert!(!d.is_new("BTC", 1)); // competing publisher's copy
207	        assert!(d.is_new("BTC", 2));
208	    }
209	
210	    #[test]
211	    fn trade_keys_independent_and_window_evicts() {
212	        let mut d: WindowedDedup<&str, u64> = WindowedDedup::new(2);
213	        assert!(d.is_new("BTC", 1));
214	        assert!(d.is_new("ETH", 1)); // same id, different key
215	        assert!(d.is_new("BTC", 2));
216	        assert!(d.is_new("BTC", 3)); // window {2,3}; id 1 evicted
217	        assert!(d.is_new("BTC", 1)); // 1 fell out of the window -> treated as new
218	    }
219	}
