1	//! Per-protocol frame processors: the [`FrameProcessor`] implementations the receiver's shared
2	//! driver dispatches to. Each owns its protocol state (reference-data state machine, sequence
3	//! tracker, warn-once flags, book state) and turns decoded frames into normalized `FeedMessage`s.
4	//!
5	//! - [`TobProcessor`] - Top-of-Book & Trades (`codec`, magic `0x445A`).
6	//! - [`MidpointProcessor`] - Midpoint (`codec_midpoint`, magic `0x4D44`).
7	//! - [`MboProcessor`] - Market-by-Order (`codec_mbo`, magic `0x4444`): reconstructs the L3 book
8	//!   in [`crate::ingest::book`] and re-serves it as full-state `depth` + `trade`.
9	
10	use std::{
11	    collections::{BTreeSet, HashMap},
12	    net::IpAddr,
13	};
14	
15	use tracing::{debug, info, warn};
16	
17	use crate::{
18	    ingest::{
19	        arbiter::{StalenessFloor, WindowedDedup},
20	        book::{BookState, DeltaKind, DeltaOp},
21	        codec::{
22	            aggressor_side, apply_exponent, decode_frame, source_name, InstrumentDefinition,
23	            Message,
24	        },
25	        codec_mbo, codec_midpoint,
26	        receiver::{FrameCtx, FrameProcessor, SeqCheck, SeqTracker},
27	        subscriber::RefDataState,
28	    },
29	    model::{
30	        DepthSnapshot, FeedMessage, NormalizedDepth, NormalizedInstrument, NormalizedMidpoint,
31	        NormalizedQuote, NormalizedTrade,
32	    },
33	};
34	
35	/// How many price levels per side a `depth` snapshot carries.
36	const DEPTH_LEVELS: usize = 10;
37	
38	/// Recent trade IDs remembered per (venue, symbol) for cross-publisher trade dedup. Const for now;
39	/// promote to config alongside the multi-publisher trade test that can size it.
40	const TRADE_DEDUP_WINDOW: usize = 8192;
41	
42	/// The raw top-of-book identity of a quote, used as the per-tick content key for the quote dedup
43	/// floor. Compares the raw fixed-point BBO fields **plus the instrument exponents** and EXCLUDES
44	/// `source_ts` (tracked separately by the floor): two BBOs with the same raw ints but different
45	/// exponents are distinct prices, and the exponents are carried so a registry/precision change can't
46	/// false-dedup them. Identical content at the same `source_ts` — a republish or the other
47	/// publisher's copy — is a true duplicate.
48	#[derive(Clone, Copy, PartialEq, Eq, Hash)]
49	struct QuoteContent {
50	    bid_price_raw: i64,
51	    bid_qty_raw: u64,
52	    ask_price_raw: i64,
53	    ask_qty_raw: u64,
54	    price_exponent: i8,
55	    qty_exponent: i8,
56	}
57	
58	/// Insert or replace an instrument definition in the shared snapshot, warning if an existing
59	/// entry for the same `(venue, symbol)` carries different exponents. When one venue is served by
60	/// multiple feeds (e.g. Hyperliquid TOB + MBO), both write the same key; they are expected to
61	/// agree on precision, so a disagreement is a publisher inconsistency worth surfacing rather than
62	/// silently clobbering.
63	fn upsert_instrument(instruments: &crate::model::InstrumentSnapshot, inst: &NormalizedInstrument) {
64	    let key = (inst.venue.clone(), inst.symbol.clone());
65	    let mut map = instruments.lock().unwrap();
66	    if let Some(prev) = map.get(&key) {
67	        if prev.price_exponent != inst.price_exponent || prev.qty_exponent != inst.qty_exponent {
68	            warn!(
69	                venue = inst.venue,
70	                symbol = inst.symbol,
71	                prev_price_exp = prev.price_exponent,
72	                new_price_exp = inst.price_exponent,
73	                prev_qty_exp = prev.qty_exponent,
74	                new_qty_exp = inst.qty_exponent,
75	                "conflicting instrument definitions for the same (venue, symbol) across feeds; last writer wins"
76	            );
77	        }
78	    }
79	    map.insert(key, inst.clone());
80	}
