82	/// Top-of-Book & Trades processor: drives the reference-data state machine on the refdata stream
83	/// and emits normalized quotes (gated per-instrument on a known definition) on the market-data
84	/// stream. Holds the per-channel sequence tracker used to drop stale/out-of-order quote frames.
85	pub struct TobProcessor {
86	    state: RefDataState<InstrumentDefinition>,
87	    /// Per-publisher, per-channel frame sequence tracker. Independent publishers mirror this feed
88	    /// onto one group sharing `channel_id=0`, so a single tracker would mark the slower publisher's
89	    /// frames stale and drop them before dedup; keying by source IP keeps each publisher's sequence
90	    /// state separate.
91	    seq: HashMap<IpAddr, SeqTracker>,
92	    /// Log the manifest `Valid=0` publisher workaround once, not on every (~1/s) manifest.
93	    warned_invalid_manifest: bool,
94	    /// Log an unregistered quote SourceID once, not on every quote.
95	    warned_source_mismatch: bool,
96	    /// Whether to emit `trade` messages (false when another feed owns this venue's trades).
97	    emit_trades: bool,
98	    /// Cross-publisher quote dedup: a per-(venue, symbol) `source_ts` latch-to-leader floor keyed on
99	    /// raw BBO content and the source IP. Within one `source_ts` tick it emits only the leader (first
100	    /// publisher to open the tick) and drops other publishers' samples, because arrival order across
101	    /// delayed publishers can't be trusted (a slower publisher's older sample landing last would read
102	    /// as a phantom change). Drops a strictly-older BBO (stale laggard) and the leader's exact
103	    /// `(source_ts, content)` repeats. Output `source_ts` is non-decreasing per (venue, symbol).
104	    quote_dedup: StalenessFloor<(String, String), QuoteContent, IpAddr>,
105	    /// Cross-publisher trade dedup by venue trade_id per (venue, symbol).
106	    trade_dedup: WindowedDedup<(String, String), u64>,
107	}
108	
109	impl TobProcessor {
110	    pub fn new(emit_trades: bool) -> Self {
111	        Self {
112	            state: RefDataState::new(),
113	            seq: HashMap::new(),
114	            warned_invalid_manifest: false,
115	            warned_source_mismatch: false,
116	            emit_trades,
117	            quote_dedup: StalenessFloor::new(),
118	            trade_dedup: WindowedDedup::new(TRADE_DEDUP_WINDOW),
119	        }
120	    }
121	
122	    /// Whether this quote should be forwarded under the per-(venue, symbol) latch-to-leader floor:
123	    /// true if `source_ts` is at or beyond the floor AND (it opens a new tick, or `publisher` is the
124	    /// tick's latched leader and the `content` is new). Drops strictly-older (stale laggard) BBOs,
125	    /// non-leader samples within a tick, and the leader's exact `(source_ts, content)` repeats.
126	    fn admit_quote(
127	        &mut self,
128	        venue: &str,
129	        symbol: &str,
130	        source_ts: u64,
131	        content: QuoteContent,
132	        publisher: IpAddr,
133	    ) -> bool {
134	        self.quote_dedup.admit(
135	            (venue.to_string(), symbol.to_string()),
136	            source_ts,
137	            content,
138	            publisher,
139	        )
140	    }
141	
142	    /// Whether this trade should be forwarded: false if its trade_id was seen recently.
143	    fn admit_trade(&mut self, venue: &str, symbol: &str, trade_id: u64) -> bool {
144	        self.trade_dedup
145	            .is_new((venue.to_string(), symbol.to_string()), trade_id)
146	    }
147	}
