149	impl FrameProcessor for TobProcessor {
150	    fn on_datagram(&mut self, buf: &[u8], ctx: &FrameCtx) {
151	        let (header, messages) = match decode_frame(buf) {
152	            Ok(v) => v,
153	            Err(e) => {
154	                warn!(role = ?ctx.role, "decode error: {e}");
155	                return;
156	            }
157	        };
158	
159	        let handle_refdata = ctx.role.handles_refdata();
160	        let handle_quotes = ctx.role.handles_mktdata();
161	
162	        if handle_refdata {
163	            self.state.on_frame(header.reset_count);
164	        }
165	
166	        // Per edge-feed-spec, the frame Sequence Number is monotonically increasing per channel and
167	        // a `Reset Count` change signals a publisher reset. On the quote feed we drop only the stale
168	        // (out-of-order/replayed) frames - those whose sequence is below the last seen within the
169	        // same reset epoch - so an old datagram can never overwrite a fresher top-of-book. Forward
170	        // jumps are accepted without comment (the channel-0 sequence is global across groups, so
171	        // per-group gaps are expected, not loss).
172	        let quotes_fresh = if handle_quotes {
173	            match self.seq.entry(ctx.publisher).or_default().check(
174	                header.channel_id,
175	                header.reset_count,
176	                header.sequence,
177	            ) {
178	                SeqCheck::Stale => {
179	                    debug!(
180	                        venue = ctx.venue,
181	                        channel = header.channel_id,
182	                        sequence = header.sequence,
183	                        "dropping stale/out-of-order quote frame (sequence below last seen)"
184	                    );
185	                    false
186	                }
187	                SeqCheck::Reset => {
188	                    info!(
189	                        venue = ctx.venue,
190	                        channel = header.channel_id,
191	                        reset_count = header.reset_count,
192	                        sequence = header.sequence,
193	                        "quote channel reset; sequence restarted"
194	                    );
195	                    true
196	                }
197	                SeqCheck::First | SeqCheck::Ok => true,
198	            }
199	        } else {
200	            true
201	        };
202	
203	        for msg in messages {
204	            match msg {
205	                Message::ManifestSummary(m) if handle_refdata => {
206	                    // TEMP WORKAROUND: the live DZ Edge HL publisher currently emits
207	                    // ManifestSummary with Valid=0 (verified against edge-feed-spec: the
208	                    // Valid byte at message offset 5 is genuinely 0x00, not a decode bug),
209	                    // even though Quotes and the SOL InstrumentDefinition flow correctly.
210	                    // Per spec Valid=0 means "no established instrument set", which would
211	                    // keep RefDataState from ever reaching ready() and block all quotes.
212	                    // Until the publisher is fixed to emit Valid=1, force valid=true here so
213	                    // the bridge can consume the otherwise-healthy feed. REVISIT: drop this
214	                    // override and pass `m.valid` once the publisher manifest is corrected.
215	                    if !m.valid && !self.warned_invalid_manifest {
216	                        self.warned_invalid_manifest = true;
217	                        warn!(
218	                            manifest_seq = m.manifest_seq,
219	                            instrument_count = m.instrument_count,
220	                            "manifest Valid=0 from publisher; overriding to valid (temporary, logged once)"
221	                        );
222	                    }
223	                    self.state
224	                        .on_manifest(true, m.manifest_seq, m.instrument_count);
225	                }
226	                Message::InstrumentDefinition(d) if handle_refdata => {
227	                    let inst = NormalizedInstrument {
228	                        venue: ctx.venue.to_string(),
229	                        symbol: d.symbol.clone(),
230	                        price_exponent: d.price_exponent,
231	                        qty_exponent: d.qty_exponent,
232	                    };
233	                    // Update the shared snapshot so newly-connecting subscribers get this
234	                    // instrument before any quote.
235	                    upsert_instrument(ctx.instruments, &inst);
236	                    self.state.on_instrument_definition(d);
237	                    let _ = ctx.tx.send(FeedMessage::Instrument(inst));
238	                }
239	                Message::ChannelReset(ts) if handle_refdata => {
240	                    warn!(ts, "channel reset; discarding reference-data state");
241	                    self.state = RefDataState::new();
242	                }
243	                Message::EndOfSession(ts) if handle_refdata => {
244	                    info!(ts, "end of session");
245	                }
246	                Message::Quote(q) if handle_quotes && quotes_fresh => {
247	                    // Per-instrument readiness: emit a quote as soon as we hold *this*
248	                    // instrument's definition, rather than gating on the whole set being
249	                    // complete (`state.ready()`). This still upholds the precision guarantee
250	                    // - we never emit a price without knowing its exponents, because the
251	                    // definition lookup below supplies them - but it removes the fragility of
252	                    // the all-or-nothing gate. Instrument definitions arrive in an infrequent
253	                    // burst (~every 8s on the live Phoenix feed) while quotes stream
254	                    // continuously, so a startup/reset race that left `defs` short of
255	                    // `expected_count` would otherwise wedge the feed: every quote dropped
256	                    // until a *full* burst landed within a single valid manifest epoch.
257	                    // Gating per instrument lets each symbol's quotes flow the moment its
258	                    // definition is known, independent of the others.
259	                    let Some(def) = self.state.definition(q.instrument_id) else {
260	                        continue; // no definition for this instrument yet; drop until we have it
261	                    };
262	                    // This feed maps to a single venue (see feeds.rs), so instruments and quotes
263	                    // are tagged alike with it. Cross-check the wire SourceID against the source
264	                    // registry and warn once if it names a different venue - that means the feed
265	                    // table and the wire disagree about what this group carries.
266	                    if let Some(name) = source_name(q.source_id) {
267	                        if name != ctx.venue && !self.warned_source_mismatch {
268	                            self.warned_source_mismatch = true;
269	                            warn!(
270	                                source_id = q.source_id, registry_venue = name, feed_venue = %ctx.venue,
271	                                "quote SourceID maps to a venue different from this feed's venue (logged once)"
272	                            );
273	                        }
274	                    }
275	                    let quote = NormalizedQuote {
276	                        // Venue is the wire SourceID's registered venue (2 -> Phoenix); anything
277	                        // unregistered (the source_id 3 Hyperliquid superset incl. HIP-3 builder
278	                        // DEXs) falls back to the feed default (Hyperliquid). So venues are exactly
279	                        // Hyperliquid + Phoenix; the builder DEX, if any, stays in the symbol.
280	                        venue: source_name(q.source_id).unwrap_or(ctx.venue).to_string(),
281	                        symbol: def.symbol.clone(),
282	                        bid: apply_exponent(q.bid_price_raw, def.price_exponent),
283	                        ask: apply_exponent(q.ask_price_raw, def.price_exponent),
284	                        bid_size: apply_exponent(q.bid_qty_raw as i64, def.qty_exponent),
285	                        ask_size: apply_exponent(q.ask_qty_raw as i64, def.qty_exponent),
286	                        source_ts_ns: q.source_ts,
287	                        recv_ts_ns: ctx.recv_ts_ns,
288	                        kernel_rx_ts_ns: ctx.kernel_rx_ts_ns,
289	                        ws_send_ts_ns: 0, // stamped by the WS server just before send
290	                    };
291	                    // Cross-publisher dedup on a per-(venue, symbol) source_ts latch-to-leader floor:
292	                    // within one source_ts tick only the leader (first publisher to open it) is
293	                    // emitted — a slower publisher's samples at the same tick arrive in a
294	                    // delay-corrupted order and can't be trusted, so they are dropped. A strictly-
295	                    // older sample (stale laggard) and the leader's exact (source_ts, content)
296	                    // repeats are dropped too. Output source_ts is non-decreasing per (venue, symbol).
297	                    let content = QuoteContent {
298	                        bid_price_raw: q.bid_price_raw,
299	                        bid_qty_raw: q.bid_qty_raw,
300	                        ask_price_raw: q.ask_price_raw,
301	                        ask_qty_raw: q.ask_qty_raw,
302	                        price_exponent: def.price_exponent,
303	                        qty_exponent: def.qty_exponent,
304	                    };
305	                    if self.admit_quote(
306	                        &quote.venue,
307	                        &quote.symbol,
308	                        quote.source_ts_ns,
309	                        content,
310	                        ctx.publisher,
311	                    ) {
312	                        let _ = ctx.tx.send(FeedMessage::Quote(quote));
313	                    }
314	                }
315	                Message::Trade(t) if handle_quotes && quotes_fresh => {
316	                    // Same per-instrument precision gate as quotes: a trade is dropped until we
317	                    // hold its definition, so we never emit a price without knowing its exponents.
318	                    let Some(def) = self.state.definition(t.instrument_id) else {
319	                        continue;
320	                    };
321	                    let trade = NormalizedTrade {
322	                        venue: source_name(t.source_id).unwrap_or(ctx.venue).to_string(),
323	                        symbol: def.symbol.clone(),
324	                        price: apply_exponent(t.trade_price_raw, def.price_exponent),
325	                        size: apply_exponent(t.trade_qty_raw as i64, def.qty_exponent),
326	                        aggressor_side: aggressor_side(t.aggressor_side).to_string(),
327	                        trade_id: t.trade_id,
328	                        cumulative_volume: apply_exponent(
329	                            t.cumulative_volume_raw as i64,
330	                            def.qty_exponent,
331	                        ),
332	                        source_ts_ns: t.source_ts,
333	                        recv_ts_ns: ctx.recv_ts_ns,
334	                        kernel_rx_ts_ns: ctx.kernel_rx_ts_ns,
335	                        ws_send_ts_ns: 0, // stamped by the WS server just before send
336	                    };
337	                    if self.emit_trades
338	                        && self.admit_trade(&trade.venue, &trade.symbol, trade.trade_id)
339	                    {
340	                        let _ = ctx.tx.send(FeedMessage::Trade(trade));
341	                    }
342	                }
343	                _ => {}
344	            }
345	        }
346	    }
347	}
