349	/// Midpoint processor: drives the reference-data state machine on the refdata stream and emits a
350	/// normalized mid price (gated per-instrument on a known definition) on the market-data stream.
351	/// Structurally parallel to [`TobProcessor`] but for the `0x4D44` sibling protocol.
352	pub struct MidpointProcessor {
353	    state: RefDataState<codec_midpoint::InstrumentDefinition>,
354	    seq: SeqTracker,
355	    warned_source_mismatch: bool,
356	}
357	
358	impl Default for MidpointProcessor {
359	    fn default() -> Self {
360	        Self::new()
361	    }
362	}
363	
364	impl MidpointProcessor {
365	    pub fn new() -> Self {
366	        Self {
367	            state: RefDataState::new(),
368	            seq: SeqTracker::default(),
369	            warned_source_mismatch: false,
370	        }
371	    }
372	}
373	
374	impl FrameProcessor for MidpointProcessor {
375	    fn on_datagram(&mut self, buf: &[u8], ctx: &FrameCtx) {
376	        let (header, messages) = match codec_midpoint::decode_frame(buf) {
377	            Ok(v) => v,
378	            Err(e) => {
379	                warn!(role = ?ctx.role, "midpoint decode error: {e}");
380	                return;
381	            }
382	        };
383	
384	        let handle_refdata = ctx.role.handles_refdata();
385	        let handle_mids = ctx.role.handles_mktdata();
386	
387	        if handle_refdata {
388	            self.state.on_frame(header.reset_count);
389	        }
390	
391	        // Same stale/out-of-order rejection as quotes: a midpoint is full state per instrument.
392	        let mids_fresh = if handle_mids {
393	            !matches!(
394	                self.seq
395	                    .check(header.channel_id, header.reset_count, header.sequence),
396	                SeqCheck::Stale
397	            )
398	        } else {
399	            true
400	        };
401	
402	        for msg in messages {
403	            match msg {
404	                codec_midpoint::Message::ManifestSummary(m) if handle_refdata => {
405	                    // Unlike the Top-of-Book HL publisher (which emits Valid=0 - see TobProcessor),
406	                    // we pass the Midpoint manifest's `valid` honestly; if the Midpoint publisher
407	                    // turns out to share that defect, apply the same override here.
408	                    self.state
409	                        .on_manifest(m.valid, m.manifest_seq, m.instrument_count);
410	                }
411	                codec_midpoint::Message::InstrumentDefinition(d) if handle_refdata => {
412	                    // A mid price has no size, so there is no qty exponent on the Midpoint feed;
413	                    // report qty_exponent = 0 in the shared snapshot (consumers ignore it for mids).
414	                    let inst = NormalizedInstrument {
415	                        venue: ctx.venue.to_string(),
416	                        symbol: d.symbol.clone(),
417	                        price_exponent: d.price_exponent,
418	                        qty_exponent: 0,
419	                    };
420	                    upsert_instrument(ctx.instruments, &inst);
421	                    self.state.on_instrument_definition(d);
422	                    let _ = ctx.tx.send(FeedMessage::Instrument(inst));
423	                }
424	                codec_midpoint::Message::EndOfSession(ts) if handle_refdata => {
425	                    info!(ts, "midpoint end of session");
426	                }
427	                codec_midpoint::Message::Midpoint(mp) if handle_mids && mids_fresh => {
428	                    let Some(def) = self.state.definition(mp.instrument_id) else {
429	                        continue; // no definition yet; drop until we know precision
430	                    };
431	                    if let Some(name) = source_name(mp.source_id) {
432	                        if name != ctx.venue && !self.warned_source_mismatch {
433	                            self.warned_source_mismatch = true;
434	                            warn!(
435	                                source_id = mp.source_id, registry_venue = name, feed_venue = %ctx.venue,
436	                                "midpoint SourceID maps to a venue different from this feed's venue (logged once)"
437	                            );
438	                        }
439	                    }
440	                    let midpoint = NormalizedMidpoint {
441	                        venue: source_name(mp.source_id).unwrap_or(ctx.venue).to_string(),
442	                        symbol: def.symbol.clone(),
443	                        mid: apply_exponent(mp.mid_price_raw, def.price_exponent),
444	                        method: mp.method,
445	                        quality_flags: mp.quality_flags,
446	                        book_ts_ns: mp.book_ts,
447	                        compute_ts_ns: mp.compute_ts,
448	                        recv_ts_ns: ctx.recv_ts_ns,
449	                        kernel_rx_ts_ns: ctx.kernel_rx_ts_ns,
450	                        ws_send_ts_ns: 0, // stamped by the WS server just before send
451	                    };
452	                    let _ = ctx.tx.send(FeedMessage::Midpoint(midpoint));
453	                }
454	                _ => {}
455	            }
456	        }
457	    }
458	}
