460	/// Market-by-Order processor: drives the reference-data state machine (refdata port), feeds order
461	/// deltas and the snapshot stream into a per-instrument [`BookState`] (mktdata + snapshot ports),
462	/// and emits a full-state `depth` snapshot whenever an instrument's top-N changes - plus `trade`
463	/// prints. The reconstructed book lives here so consumers never see raw deltas (PROTOCOL.md).
464	pub struct MboProcessor {
465	    state: RefDataState<codec_mbo::InstrumentDefinition>,
466	    books: HashMap<u32, BookState>,
467	    /// Shared latest-depth map the WS server replays on connect.
468	    depth: DepthSnapshot,
469	    warned_source_mismatch: bool,
470	    /// Whether to emit `trade` messages (false when another feed owns this venue's trades).
471	    emit_trades: bool,
472	}
473	
474	impl MboProcessor {
475	    pub fn new(depth: DepthSnapshot, emit_trades: bool) -> Self {
476	        Self {
477	            state: RefDataState::new(),
478	            books: HashMap::new(),
479	            depth,
480	            warned_source_mismatch: false,
481	            emit_trades,
482	        }
483	    }
484	
485	    /// Build and broadcast a full-state `depth` snapshot for one instrument, updating the shared
486	    /// replay map. No-op unless the book is synced and the instrument's precision is known.
487	    fn emit_depth(&mut self, instrument_id: u32, ctx: &FrameCtx) {
488	        let Some(book) = self.books.get(&instrument_id) else {
489	            return;
490	        };
491	        if !book.is_synced() {
492	            return;
493	        }
494	        let Some(def) = self.state.definition(instrument_id) else {
495	            return; // precision unknown; don't emit a book we can't scale
496	        };
497	        let (bids_raw, asks_raw) = book.top_levels(DEPTH_LEVELS);
498	        let scale = |levels: Vec<(i64, u64)>| -> Vec<[f64; 2]> {
499	            levels
500	                .into_iter()
501	                .map(|(p, q)| {
502	                    [
503	                        apply_exponent(p, def.price_exponent),
504	                        apply_exponent(q as i64, def.qty_exponent),
505	                    ]
506	                })
507	                .collect()
508	        };
509	        let depth = NormalizedDepth {
510	            venue: ctx.venue.to_string(),
511	            symbol: def.symbol.clone(),
512	            bids: scale(bids_raw),
513	            asks: scale(asks_raw),
514	            source_ts_ns: book.last_event_ts(),
515	            recv_ts_ns: ctx.recv_ts_ns,
516	            kernel_rx_ts_ns: ctx.kernel_rx_ts_ns,
517	            ws_send_ts_ns: 0, // stamped by the WS server just before send
518	        };
519	        self.depth
520	            .lock()
521	            .unwrap()
522	            .insert((depth.venue.clone(), depth.symbol.clone()), depth.clone());
523	        let _ = ctx.tx.send(FeedMessage::Depth(depth));
524	    }
525	}
