527	impl FrameProcessor for MboProcessor {
528	    fn on_datagram(&mut self, buf: &[u8], ctx: &FrameCtx) {
529	        let (header, messages) = match codec_mbo::decode_frame(buf) {
530	            Ok(v) => v,
531	            Err(e) => {
532	                warn!(role = ?ctx.role, "mbo decode error: {e}");
533	                return;
534	            }
535	        };
536	
537	        if ctx.role.handles_refdata() {
538	            self.state.on_frame(header.reset_count);
539	        }
540	
541	        // Instruments whose book changed this frame; depth is emitted once per frame per instrument
542	        // (coalescing many order events into a single full-state snapshot). BTreeSet gives
543	        // deterministic ascending instrument_id order across frames touching multiple instruments.
544	        let mut changed: BTreeSet<u32> = BTreeSet::new();
545	
546	        for msg in messages {
547	            match msg {
548	                codec_mbo::Message::ManifestSummary(m) => {
549	                    self.state
550	                        .on_manifest(m.valid, m.manifest_seq, m.instrument_count);
551	                }
552	                codec_mbo::Message::InstrumentDefinition(d) => {
553	                    let inst = NormalizedInstrument {
554	                        venue: ctx.venue.to_string(),
555	                        symbol: d.symbol.clone(),
556	                        price_exponent: d.price_exponent,
557	                        qty_exponent: d.qty_exponent,
558	                    };
559	                    upsert_instrument(ctx.instruments, &inst);
560	                    self.state.on_instrument_definition(d);
561	                    let _ = ctx.tx.send(FeedMessage::Instrument(inst));
562	                }
563	                codec_mbo::Message::EndOfSession(ts) => info!(ts, "mbo end of session"),
564	                codec_mbo::Message::OrderAdd(o) => {
565	                    let op = DeltaOp {
566	                        seq: o.per_instrument_seq,
567	                        mktdata_seq: header.sequence,
568	                        ts: o.enter_ts,
569	                        kind: DeltaKind::Add {
570	                            order_id: o.order_id,
571	                            is_bid: o.side == codec_mbo::SIDE_BID,
572	                            price_raw: o.price_raw,
573	                            qty_raw: o.qty_raw,
574	                        },
575	                    };
576	                    if self.books.entry(o.instrument_id).or_default().on_delta(op) {
577	                        changed.insert(o.instrument_id);
578	                    }
579	                }
580	                codec_mbo::Message::OrderCancel(o) => {
581	                    let op = DeltaOp {
582	                        seq: o.per_instrument_seq,
583	                        mktdata_seq: header.sequence,
584	                        ts: o.ts,
585	                        kind: DeltaKind::Cancel {
586	                            order_id: o.order_id,
587	                        },
588	                    };
589	                    if self.books.entry(o.instrument_id).or_default().on_delta(op) {
590	                        changed.insert(o.instrument_id);
591	                    }
592	                }
593	                codec_mbo::Message::OrderExecute(o) => {
594	                    let op = DeltaOp {
595	                        seq: o.per_instrument_seq,
596	                        mktdata_seq: header.sequence,
597	                        ts: o.ts,
598	                        kind: DeltaKind::Execute {
599	                            order_id: o.order_id,
600	                            exec_qty_raw: o.exec_qty_raw,
601	                            full_fill: o.exec_flags & 0x01 != 0,
602	                        },
603	                    };
604	                    if self.books.entry(o.instrument_id).or_default().on_delta(op) {
605	                        changed.insert(o.instrument_id);
606	                    }
607	                    // An execution is also a public trade print; emit it like a Top-of-Book trade.
608	                    if let Some(def) = self.state.definition(o.instrument_id) {
609	                        let trade = NormalizedTrade {
610	                            venue: ctx.venue.to_string(),
611	                            symbol: def.symbol.clone(),
612	                            price: apply_exponent(o.exec_price_raw, def.price_exponent),
613	                            size: apply_exponent(o.exec_qty_raw as i64, def.qty_exponent),
614	                            aggressor_side: aggressor_side(o.aggressor_side).to_string(),
615	                            trade_id: o.trade_id,
616	                            cumulative_volume: 0.0,
617	                            source_ts_ns: o.ts,
618	                            recv_ts_ns: ctx.recv_ts_ns,
619	                            kernel_rx_ts_ns: ctx.kernel_rx_ts_ns,
620	                            ws_send_ts_ns: 0,
621	                        };
622	                        if self.emit_trades {
623	                            let _ = ctx.tx.send(FeedMessage::Trade(trade));
624	                        }
625	                    }
626	                }
627	                codec_mbo::Message::Trade(t) => {
628	                    let Some(def) = self.state.definition(t.instrument_id) else {
629	                        continue;
630	                    };
631	                    let trade = NormalizedTrade {
632	                        venue: source_name(t.source_id).unwrap_or(ctx.venue).to_string(),
633	                        symbol: def.symbol.clone(),
634	                        price: apply_exponent(t.trade_price_raw, def.price_exponent),
635	                        size: apply_exponent(t.trade_qty_raw as i64, def.qty_exponent),
636	                        aggressor_side: aggressor_side(t.aggressor_side).to_string(),
637	                        trade_id: t.trade_id,
638	                        cumulative_volume: apply_exponent(
639	                            t.cumulative_volume_raw as i64,
640	                            def.qty_exponent,
641	                        ),
642	                        source_ts_ns: t.source_ts,
643	                        recv_ts_ns: ctx.recv_ts_ns,
644	                        kernel_rx_ts_ns: ctx.kernel_rx_ts_ns,
645	                        ws_send_ts_ns: 0,
646	                    };
647	                    if let Some(name) = source_name(t.source_id) {
648	                        if name != ctx.venue && !self.warned_source_mismatch {
649	                            self.warned_source_mismatch = true;
650	                            warn!(source_id = t.source_id, registry_venue = name, feed_venue = %ctx.venue,
651	                                  "mbo SourceID maps to a venue different from this feed's venue (logged once)");
652	                        }
653	                    }
654	                    if self.emit_trades {
655	                        let _ = ctx.tx.send(FeedMessage::Trade(trade));
656	                    }
657	                }
658	                codec_mbo::Message::InstrumentReset(r) => {
659	                    self.books
660	                        .entry(r.instrument_id)
661	                        .or_default()
662	                        .on_instrument_reset(r.new_anchor_seq);
663	                }
664	                codec_mbo::Message::SnapshotBegin(s) => {
665	                    self.books
666	                        .entry(s.instrument_id)
667	                        .or_default()
668	                        .on_snapshot_begin(
669	                            s.snapshot_id,
670	                            s.anchor_seq,
671	                            s.total_orders,
672	                            s.last_instrument_seq,
673	                        );
674	                }
675	                codec_mbo::Message::SnapshotOrder(s) => {
676	                    // SnapshotOrder carries only the snapshot_id, not the instrument id; route it to
677	                    // whichever book is currently assembling that snapshot. snapshot_id is monotonic
678	                    // per (channel, instrument) - not globally unique - but the spec forbids
679	                    // interleaving snapshot groups across instruments, so at most one book is
680	                    // `building` at a time and only it matches.
681	                    for book in self.books.values_mut() {
682	                        book.on_snapshot_order(
683	                            s.snapshot_id,
684	                            s.order_id,
685	                            s.side == codec_mbo::SIDE_BID,
686	                            s.price_raw,
687	                            s.qty_raw,
688	                        );
689	                    }
690	                }
691	                codec_mbo::Message::SnapshotEnd(s) => {
692	                    if self
693	                        .books
694	                        .entry(s.instrument_id)
695	                        .or_default()
696	                        .on_snapshot_end(s.anchor_seq, s.snapshot_id)
697	                    {
698	                        changed.insert(s.instrument_id);
699	                    }
700	                }
701	                // BatchBoundary is an emission-coalescing hint; we already emit once per frame.
702	                codec_mbo::Message::BatchBoundary(_, _) | codec_mbo::Message::Heartbeat => {}
703	                codec_mbo::Message::Other(_) => {}
704	            }
705	        }
706	
707	        for instrument_id in changed {
708	            self.emit_depth(instrument_id, ctx);
709	        }
710	    }
711	}
