761	        assert!(!p.admit_quote("Hyperliquid", "BTC", 1000, c2, b)); // B at same tick -> dropped (latch to A)
762	        assert!(!p.admit_quote("Hyperliquid", "BTC", 999, c1, a)); // strictly older (stale) dropped
763	        assert!(p.admit_quote("Hyperliquid", "BTC", 2000, c1, b)); // new tick: B opens it -> B leads, emit
