775	    /// Encode a ManifestSummary wire message (24 bytes total, valid=true).
776	    ///
777	    /// Body layout matches `codec_mbo::decode_message` offsets:
778	    ///   +0 channel_id (u8), +1 valid (u8), +2..+4 pad,
779	    ///   +4 manifest_seq (u16le), +6..+8 pad,
780	    ///   +8 instrument_count (u32le), +12 ts (u64le).
781	    fn enc_manifest_summary(manifest_seq: u16, instrument_count: u32) -> Vec<u8> {
782	        let mut out = vec![MSG_MANIFEST_SUMMARY, 24, 0, 0]; // 4-byte hdr + 20-byte body
783	        out.push(0u8); // body+0: channel_id
784	        out.push(1u8); // body+1: valid = true
785	        out.extend_from_slice(&[0u8; 2]); // body+2..+4: pad
786	        out.extend_from_slice(&manifest_seq.to_le_bytes()); // body+4..+6
787	        out.extend_from_slice(&[0u8; 2]); // body+6..+8: pad
788	        out.extend_from_slice(&instrument_count.to_le_bytes()); // body+8..+12
789	        out.extend_from_slice(&0u64.to_le_bytes()); // body+12..+20: ts
790	        out
791	    }
792	
793	    /// Encode an InstrumentDefinition wire message (80 bytes total, exponents=0).
794	    ///
795	    /// Body layout matches `codec_mbo::decode_message` offsets:
796	    ///   +0 instrument_id (u32le), +4 symbol (16 B NUL-padded),
797	    ///   +20..+37 pad, +37 price_exponent (i8), +38 qty_exponent (i8),
798	    ///   +39..+74 pad, +74 manifest_seq (u16le).
799	    /// Total: 4 (hdr) + 76 (body) = 80 bytes = sizes::INSTRUMENT_DEFINITION.
800	    fn enc_instrument_def(id: u32, symbol: &str, manifest_seq: u16) -> Vec<u8> {
801	        let mut out = vec![MSG_INSTRUMENT_DEFINITION, 80, 0, 0];
802	        out.extend_from_slice(&id.to_le_bytes()); // body+0..+4
803	        let mut sym = [0u8; 16];
804	        let sb = symbol.as_bytes();
805	        sym[..sb.len().min(16)].copy_from_slice(&sb[..sb.len().min(16)]);
806	        out.extend_from_slice(&sym); // body+4..+20
807	        out.extend_from_slice(&[0u8; 17]); // body+20..+37: pad
808	        out.push(0u8); // body+37: price_exponent = 0
809	        out.push(0u8); // body+38: qty_exponent = 0
810	        out.extend_from_slice(&[0u8; 35]); // body+39..+74: pad
811	        out.extend_from_slice(&manifest_seq.to_le_bytes()); // body+74..+76
812	                                                            // 4 + 4 + 16 + 17 + 1 + 1 + 35 + 2 = 80 bytes total.
813	        out
814	    }
