971	    /// `upsert_instrument` is idempotent for matching exponents and last-writer-wins for
972	    /// conflicting ones (exercising the warn path; the warn itself is not asserted).
973	    #[test]
974	    fn upsert_instrument_idempotent_and_last_writer_wins() {
975	        let instruments: crate::model::InstrumentSnapshot = Arc::new(Mutex::new(HashMap::new()));
976	
977	        let base = NormalizedInstrument {
978	            venue: "TestVenue".to_string(),
979	            symbol: "BTC".to_string(),
980	            price_exponent: -2,
981	            qty_exponent: -4,
982	        };
983	
984	        // First insert.
985	        upsert_instrument(&instruments, &base);
986	        {
987	            let map = instruments.lock().unwrap();
988	            assert_eq!(map.len(), 1);
989	            let entry = map
990	                .get(&("TestVenue".to_string(), "BTC".to_string()))
991	                .unwrap();
992	            assert_eq!(entry.price_exponent, -2);
993	            assert_eq!(entry.qty_exponent, -4);
994	        }
995	
996	        // Second insert with identical exponents — idempotent, still one entry.
997	        upsert_instrument(&instruments, &base);
998	        assert_eq!(instruments.lock().unwrap().len(), 1);
999	
1000	        // Third insert with DIFFERENT exponents — exercises the divergence warn path.
1001	        // Last writer wins: the snapshot ends with the new exponents.
1002	        let conflicting = NormalizedInstrument {
1003	            price_exponent: -3,
1004	            qty_exponent: -5,
1005	            ..base.clone()
1006	        };
1007	        upsert_instrument(&instruments, &conflicting);
1008	        {
1009	            let map = instruments.lock().unwrap();
1010	            assert_eq!(map.len(), 1, "still one entry after conflicting write");
1011	            let entry = map
1012	                .get(&("TestVenue".to_string(), "BTC".to_string()))
1013	                .unwrap();
1014	            assert_eq!(
1015	                entry.price_exponent, -3,
1016	                "last writer's price_exponent wins"
1017	            );
1018	            assert_eq!(entry.qty_exponent, -5, "last writer's qty_exponent wins");
1019	        }
1020	    }
