1	//! DoubleZero Edge multicast receiver: bind the group's port(s), decode frames, and broadcast
2	//! normalized `FeedMessage`s.
3	//!
4	//! The socket plumbing here is **protocol-agnostic** and shared by every edge-feed-spec feed:
5	//! interface resolution, the multicast join, kernel RX timestamps, the idle-rejoin watchdog and
6	//! the venue feed-health status. The per-protocol work (which frame magic, which messages, what
7	//! to emit) lives behind the [`FrameProcessor`] trait, so [`drive`] runs the same receive loop
8	//! over 1, 2 or 3 ports for Top-of-Book, Midpoint or Market-by-Order alike.
9	//!
10	//! Socket setup follows the DoubleZero edge-multicast-ref `kernel-receiver` reference:
11	//! resolve the interface name (e.g. `doublezero1`) to its IPv4 for `join_multicast_v4`,
12	//! set `SO_REUSEADDR`/`SO_REUSEPORT`, and a large `SO_RCVBUF`.
13	
14	use std::{
15	    collections::HashMap,
16	    net::{IpAddr, Ipv4Addr, SocketAddrV4},
17	    os::fd::AsRawFd,
18	    time::Duration,
19	};
20	
21	use anyhow::{bail, Context, Result};
22	use futures_util::future::select_all;
23	use nix::sys::socket::{
24	    recvmsg, setsockopt, sockopt::ReceiveTimestampns, ControlMessageOwned, MsgFlags,
25	    SockaddrStorage,
26	};
27	use socket2::{Domain, Protocol, Socket, Type};
28	use tokio::{io::unix::AsyncFd, sync::broadcast, time::timeout};
29	use tracing::{info, warn};
30	
31	/// Re-join the multicast group(s) if no datagram arrives for this long. Guards against a join
32	/// that landed on the wrong interface (e.g. the bridge started before `doublezero1` had an IP and
33	/// fell back to the default interface) or a silently wedged socket: when it fires the receiver
34	/// re-resolves the interface and rebinds, so the feed self-heals without an operator restart.
35	const IDLE_REJOIN: Duration = Duration::from_secs(30);
36	
37	/// While waiting for the configured interface to acquire an IPv4, retry this often.
38	const IFACE_POLL: Duration = Duration::from_millis(500);
39	
40	use crate::{
41	    ingest::{
42	        feeds::{Feed, FeedKind, FeedPorts},
43	        processor::{MboProcessor, MidpointProcessor, TobProcessor},
44	    },
45	    model::{now_ns, DepthSnapshot, FeedMessage, FeedStatus, InstrumentSnapshot},
46	};
47	
48	/// A multicast socket with kernel RX software timestamps enabled.
49	type TsSocket = AsyncFd<std::net::UdpSocket>;
50	
51	/// The role a feed's port plays. The market-data stream is what the liveness watchdog tracks
52	/// (reference/snapshot ports keep ticking even when market data is wedged); a processor uses the
53	/// role to decide which message families to act on for a given datagram.
54	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
55	pub enum PortRole {
56	    /// Market data: quotes / midpoints / order deltas + trades. Resets the watchdog.
57	    Mktdata,
58	    /// Reference data: instrument definitions + manifest.
59	    Refdata,
60	    /// Market-by-Order snapshot recovery stream. (Constructed once the MBO receiver lands.)
61	    #[allow(dead_code)]
62	    Snapshot,
63	    /// A single port carrying everything (loopback demo): both market and reference data.
64	    Combined,
65	}
66	
67	impl PortRole {
68	    /// Whether a processor should handle reference-data messages received on this role.
69	    pub fn handles_refdata(self) -> bool {
70	        matches!(self, PortRole::Refdata | PortRole::Combined)
71	    }
72	    /// Whether a processor should handle market-data (quote/trade/etc.) messages on this role.
73	    pub fn handles_mktdata(self) -> bool {
74	        matches!(self, PortRole::Mktdata | PortRole::Combined)
75	    }
76	}
77	
78	/// Per-datagram context handed to a [`FrameProcessor`]: the shared sinks plus the receive
79	/// timestamps and which port role the datagram arrived on. Borrowed for the duration of one
80	/// `on_datagram` call so the processor only needs to hold its own protocol state.
81	pub struct FrameCtx<'a> {
82	    pub venue: &'a str,
83	    pub tx: &'a broadcast::Sender<FeedMessage>,
84	    pub instruments: &'a InstrumentSnapshot,
85	    /// Kernel `SCM_TIMESTAMPNS` RX timestamp (CLOCK_REALTIME), or 0 if unavailable.
86	    pub kernel_rx_ts_ns: u64,
87	    /// User-space wall clock sampled right after the recv syscall returned.
88	    pub recv_ts_ns: u64,
89	    /// Which port this datagram arrived on.
90	    pub role: PortRole,
91	    /// Source IP of the datagram — the publisher identity. Independent publishers mirror one feed
92	    /// onto the same group (sharing `channel_id`), so per-publisher state (sequence tracking, MBO
93	    /// books) keys on this rather than the port.
94	    pub publisher: IpAddr,
95	}
96	
97	/// Protocol-specific frame handling. Implementors own their decode (they know their frame magic
98	/// and message set) and their persistent state (reference-data state machine, sequence trackers,
99	/// book state, warn-once flags), and emit normalized `FeedMessage`s onto `ctx.tx`.
100	pub trait FrameProcessor {
101	    /// Decode and handle one received datagram. Errors are the processor's own concern (it logs
102	    /// and drops); the driver only deals with socket/transport errors.
103	    fn on_datagram(&mut self, buf: &[u8], ctx: &FrameCtx);
104	}
105	
106	/// Broadcast a venue-level feed-health transition (PROTOCOL.md `status`): `"down"` when the
107	/// market-data multicast has gone silent past [`IDLE_REJOIN`], `"ok"` when it recovers. Consumers
108	/// gray out / restore the source on these. Best-effort (ignored if no subscriber is connected).
109	fn emit_status(tx: &broadcast::Sender<FeedMessage>, venue: &str, state: &str, stale_ms: u64) {
110	    let _ = tx.send(FeedMessage::Status(FeedStatus {
111	        venue: venue.to_string(),
112	        state: state.to_string(),
113	        stale_ms,
114	        ts_ns: now_ns(),
115	    }));
116	}
117	
118	/// Receive one datagram, returning `(len, kernel_rx_ns, user_recv_ns)`.
119	///
120	/// `kernel_rx_ns` is the `SCM_TIMESTAMPNS` kernel software RX timestamp (CLOCK_REALTIME,
121	/// taken in the driver softirq before user-space), or 0 if the kernel did not attach one.
122	/// `user_recv_ns` is the wall clock sampled right after the syscall returns - the
123	/// user-space arrival, kept so the kernel-vs-userspace jitter can be quantified.
124	async fn recv_with_ts(sock: &TsSocket, buf: &mut [u8]) -> Result<(usize, u64, u64, IpAddr)> {
125	    loop {
126	        let mut guard = sock.readable().await?;
127	        let res = guard.try_io(|inner| {
128	            let fd = inner.get_ref().as_raw_fd();
129	            let mut iov = [std::io::IoSliceMut::new(buf)];
130	            let mut cmsg = nix::cmsg_space!(nix::sys::time::TimeSpec);
131	            let r = recvmsg::<SockaddrStorage>(fd, &mut iov, Some(&mut cmsg), MsgFlags::empty())
132	                .map_err(std::io::Error::from)?;
133	            let mut kernel_ns = 0u64;
134	            if let Ok(cmsgs) = r.cmsgs() {
135	                for c in cmsgs {
136	                    if let ControlMessageOwned::ScmTimestampns(ts) = c {
137	                        kernel_ns = (ts.tv_sec() as u64) * 1_000_000_000 + ts.tv_nsec() as u64;
138	                    }
139	                }
140	            }
141	            let src = datagram_src_ip(r.address);
142	            Ok((r.bytes, kernel_ns, src))
143	        });
144	        match res {
145	            Ok(Ok((n, kernel_ns, src))) => return Ok((n, kernel_ns, now_ns(), src)),
146	            Ok(Err(e)) => return Err(e.into()),
147	            Err(_would_block) => continue,
148	        }
149	    }
150	}
151	
152	/// The source IP of a received datagram (its `recvmsg` source address), used to demultiplex
153	/// independent publishers that mirror one feed onto the same multicast group. Falls back to
154	/// `0.0.0.0` if the kernel attached no source address.
155	fn datagram_src_ip(addr: Option<SockaddrStorage>) -> IpAddr {
156	    addr.and_then(|a| a.as_sockaddr_in().map(|s| IpAddr::V4(s.ip())))
157	        .unwrap_or(IpAddr::V4(Ipv4Addr::UNSPECIFIED))
158	}
159	
160	/// Resolve an interface name (e.g. "doublezero1") to its IPv4 address via `ip`, without logging.
161	/// If `iface` already parses as an IPv4 address it is used directly. Returns `None` when the
162	/// interface does not exist yet or has no IPv4 (so the caller can wait/retry).
163	pub fn try_resolve_interface_ip(iface: &str) -> Option<Ipv4Addr> {
164	    if let Ok(ip) = iface.parse::<Ipv4Addr>() {
165	        return Some(ip);
166	    }
167	    let output = std::process::Command::new("ip")
168	        .args(["-4", "-o", "addr", "show", iface])
169	        .output()
170	        .ok()?;
171	    let stdout = std::str::from_utf8(&output.stdout).ok()?;
172	    for part in stdout.split_whitespace() {
173	        if let Some(ip_str) = part.split('/').next() {
174	            if let Ok(ip) = ip_str.parse::<Ipv4Addr>() {
175	                return Some(ip);
176	            }
177	        }
178	    }
179	    None
180	}
181	
182	/// Wait until the configured interface has an IPv4, then return it. Polls every [`IFACE_POLL`],
183	/// logging once a second while it waits, so a multicast join always happens on the right
184	/// interface (e.g. `doublezero1`) rather than racing the tunnel coming up and falling back to the
185	/// default interface. After `max_wait` it gives up and returns `0.0.0.0` (join on the default
186	/// interface) so a genuinely-misconfigured interface degrades rather than hanging forever.
187	async fn wait_for_interface_ip(iface: &str, max_wait: Duration) -> Ipv4Addr {
188	    if let Some(ip) = try_resolve_interface_ip(iface) {
189	        return ip;
190	    }
191	    info!(%iface, "interface has no IPv4 yet; waiting before joining multicast");
192	    let started = std::time::Instant::now();
193	    let mut last_log = started;
194	    loop {
195	        tokio::time::sleep(IFACE_POLL).await;
196	        if let Some(ip) = try_resolve_interface_ip(iface) {
197	            info!(%iface, %ip, waited_ms = started.elapsed().as_millis() as u64,
198	                  "interface is up; joining multicast");
199	            return ip;
200	        }
201	        if started.elapsed() >= max_wait {
202	            warn!(%iface, waited_s = max_wait.as_secs(),
203	                  "interface still has no IPv4 after waiting; joining on 0.0.0.0 (default interface)");
204	            return Ipv4Addr::UNSPECIFIED;
205	        }
206	        if last_log.elapsed() >= Duration::from_secs(1) {
207	            last_log = std::time::Instant::now();
208	            info!(%iface, waited_s = started.elapsed().as_secs(), "still waiting for interface");
209	        }
210	    }
211	}
212	
213	/// Join a UDP multicast group and return an async socket bound to `port`.
214	fn bind_multicast(
215	    group: Ipv4Addr,
216	    port: u16,
217	    iface_ip: Ipv4Addr,
218	    recv_buf: usize,
219	) -> Result<TsSocket> {
220	    let socket = Socket::new(Domain::IPV4, Type::DGRAM, Some(Protocol::UDP))
221	        .context("creating UDP socket")?;
222	    socket.set_reuse_address(true)?;
223	    #[cfg(unix)]
224	    socket.set_reuse_port(true)?;
225	
226	    // Bind to the multicast GROUP address (not INADDR_ANY): feeds share the mktdata/refdata
227	    // ports and differ only by group, so an INADDR_ANY bind puts every feed's sockets in one
228	    // SO_REUSEPORT set on the same port. The kernel then reuseport-hashes a group's datagrams
229	    // to ANY socket in that set regardless of which group each joined, so one venue's quotes
230	    // leak into another's receiver and get mislabeled. Binding to the group address makes the
231	    // kernel deliver only that group's datagrams to this socket, keeping feeds isolated.
232	    let bind_addr = SocketAddrV4::new(group, port);
233	    socket
234	        .bind(&bind_addr.into())
235	        .with_context(|| format!("binding to {group}:{port}"))?;
236	    socket
237	        .join_multicast_v4(&group, &iface_ip)
238	        .with_context(|| format!("join_multicast_v4 {group} on {iface_ip}"))?;
239	    socket
240	        .set_recv_buffer_size(recv_buf)
241	        .context("setting SO_RCVBUF")?;
242	    socket.set_nonblocking(true)?;
243	
244	    let std_sock: std::net::UdpSocket = socket.into();
245	    // Kernel software RX timestamps (SCM_TIMESTAMPNS). Best-effort: if the option is not
246	    // supported the bridge still works, falling back to the user-space recv timestamp.
247	    if let Err(e) = setsockopt(&std_sock, ReceiveTimestampns, &true) {
248	        warn!("SO_TIMESTAMPNS unavailable on port {port}: {e}; using user-space recv ts only");
249	    }
250	    Ok(AsyncFd::new(std_sock)?)
251	}
252	
253	/// Outcome of checking a frame's header against the per-channel sequence tracker.
254	///
255	/// Mirrors the edge-feed-spec frame-header semantics: the Sequence Number is "monotonically
256	/// increasing per channel ... Resets to 0 when `Reset Count` changes", and "Subscribers detect a
257	/// reset by comparing [`Reset Count`] against their last-seen value". Everything but
258	/// [`Stale`](SeqCheck::Stale) is processed.
259	///
260	/// We deliberately do *not* flag forward gaps: on the live feed the publisher's channel-0
261	/// sequence is effectively global/multiplexed across venues and groups, so any single multicast
262	/// group sees only a sparse slice of it - a "gap" per group is expected, not packet loss. Only a
263	/// *lower* sequence on the same group (a reorder/replay) is actionable.
264	#[derive(Debug, PartialEq, Eq)]
265	pub enum SeqCheck {
266	    /// First frame seen on this channel.
267	    First,
268	    /// Sequence at or above the last seen within the epoch (forward progress or a duplicate of
269	    /// the last). Accepted.
270	    Ok,
271	    /// `Reset Count` changed: the publisher reset the channel and the sequence restarts. Accepted.
272	    Reset,
273	    /// Sequence below the last seen within the same reset epoch - a reordered or duplicated
274	    /// datagram carrying a now-superseded update. Dropped, so an old message never overwrites
275	    /// a fresher one.
276	    Stale,
277	}
278	
279	/// Per-`channel_id` frame-sequence state for gap detection and stale-frame rejection on the
280	/// market-data feed, implementing the edge-feed-spec sequence/reset contract (see [`SeqCheck`]).
281	#[derive(Default)]
282	pub struct SeqTracker {
283	    /// channel_id -> (last reset_count, last accepted sequence)
284	    last: HashMap<u8, (u8, u64)>,
285	}
286	
287	impl SeqTracker {
288	    /// Classify a frame and advance the tracker. A reset (`reset_count` differs from the
289	    /// last-seen value, per spec) re-anchors to this frame's sequence; otherwise the sequence
290	    /// is compared within the epoch. The tracker is only advanced for accepted frames, so a
291	    /// dropped stale frame leaves the anchor on the freshest sequence.
292	    pub fn check(&mut self, channel_id: u8, reset_count: u8, sequence: u64) -> SeqCheck {
293	        match self.last.get_mut(&channel_id) {
294	            None => {
295	                self.last.insert(channel_id, (reset_count, sequence));
296	                SeqCheck::First
297	            }
298	            Some(entry) => {
299	                let (last_reset, last_seq) = *entry;
300	                if reset_count != last_reset {
301	                    *entry = (reset_count, sequence);
302	                    SeqCheck::Reset
303	                } else if sequence < last_seq {
304	                    SeqCheck::Stale // do not advance: keep the anchor on the freshest sequence
305	                } else {
306	                    *entry = (reset_count, sequence);
307	                    SeqCheck::Ok // forward progress or a duplicate of the last sequence
308	                }
309	            }
310	        }
311	    }
312	}
313	
314	/// A bound multicast socket together with its receive buffer and the role it plays.
315	struct Channel {
316	    role: PortRole,
317	    sock: TsSocket,
318	    buf: Vec<u8>,
319	}
320	
321	/// Await the next datagram across all of a feed's sockets concurrently. Returns the role it
322	/// arrived on, the channel index (so the caller can read that channel's buffer), the length, and
323	/// the kernel/user-space RX timestamps. All in-flight borrows on `channels` are released by the
324	/// time this returns, so the caller can index `channels[idx].buf`.
325	async fn recv_any(channels: &mut [Channel]) -> Result<(PortRole, usize, usize, u64, u64, IpAddr)> {
326	    let futs: Vec<_> = channels
327	        .iter_mut()
328	        .enumerate()
329	        .map(|(i, ch)| {
330	            let role = ch.role;
331	            let sock = &ch.sock;
332	            let buf = &mut ch.buf;
333	            Box::pin(async move {
334	                let (n, kernel_ns, recv_ns, src) = recv_with_ts(sock, buf).await?;
335	                Ok::<_, anyhow::Error>((role, i, n, kernel_ns, recv_ns, src))
336	            })
337	        })
338	        .collect();
339	    // `select_all` resolves on the first ready socket; dropping the rest here cancels their
340	    // (cancellation-safe) readability waits without consuming any datagram, releasing the borrows.
341	    let (res, _idx, _rest) = select_all(futs).await;
342	    res
343	}
344	
345	/// The shared receive loop for one feed, generic over its [`FrameProcessor`]. Binds every port in
346	/// `ports` on `group`, then loops receiving datagrams and handing each to `processor`. The
347	/// [`IDLE_REJOIN`] watchdog tracks the **market-data** port only (reference/snapshot ports keep
348	/// ticking even when market data is wedged), and breaks back out to re-resolve the interface and
349	/// rebind - self-healing a join that landed on the wrong interface or a wedged socket.
350	#[allow(clippy::too_many_arguments)]
351	async fn drive<P: FrameProcessor>(
352	    group: Ipv4Addr,
353	    ports: Vec<(PortRole, u16)>,
354	    iface: String,
355	    recv_buf: usize,
356	    venue: String,
357	    tx: broadcast::Sender<FeedMessage>,
358	    instruments: InstrumentSnapshot,
359	    mut processor: P,
360	) -> Result<()> {
361	    // Feed-health transition tracking: true while the market-data multicast is considered down
362	    // (silent past IDLE_REJOIN). Persists across rejoins so we emit `down`/`ok` only on the edge.
363	    let mut down = false;
364	
365	    'rejoin: loop {
366	        // Wait for the interface to acquire an IPv4 before joining, so we don't race the tunnel
367	        // coming up and fall back to the default interface.
368	        let iface_ip = wait_for_interface_ip(&iface, Duration::from_secs(60)).await;
369	
370	        let mut channels: Vec<Channel> = Vec::with_capacity(ports.len());
371	        for &(role, port) in &ports {
372	            let sock = bind_multicast(group, port, iface_ip, recv_buf)?;
373	            channels.push(Channel {
374	                role,
375	                sock,
376	                buf: vec![0u8; 2048],
377	            });
378	        }
379	        info!(%group, ?ports, %iface, %iface_ip, recv_buf, "DZ Edge multicast receiver bound");
380	
381	        // Watchdog on the market-data stream specifically: rejoin when no market-data datagram has
382	        // arrived for IDLE_REJOIN, regardless of refdata/snapshot (which keep ticking even when
383	        // market data is wedged - the exact symptom of a join on the wrong interface).
384	        let mut last_mkt = std::time::Instant::now();
385	        loop {
386	            let remaining = IDLE_REJOIN.saturating_sub(last_mkt.elapsed());
387	            if remaining.is_zero() {
388	                warn!(%group, idle_s = IDLE_REJOIN.as_secs(),
389	                      "no market data; re-resolving interface and rejoining");
390	                if !down {
391	                    emit_status(&tx, &venue, "down", last_mkt.elapsed().as_millis() as u64);
392	                    down = true;
393	                }
394	                continue 'rejoin;
395	            }
396	
397	            let (role, idx, n, kernel_ns, recv_ns, publisher) =
398	                match timeout(remaining, recv_any(&mut channels)).await {
399	                    Ok(Ok(v)) => v,
400	                    Ok(Err(e)) => {
401	                        warn!(%group, "recv error: {e}; rejoining");
402	                        continue 'rejoin;
403	                    }
404	                    Err(_) => {
405	                        warn!(%group, idle_s = IDLE_REJOIN.as_secs(),
406	                              "no market data; re-resolving interface and rejoining");
407	                        if !down {
408	                            emit_status(&tx, &venue, "down", last_mkt.elapsed().as_millis() as u64);
409	                            down = true;
410	                        }
411	                        continue 'rejoin;
412	                    }
413	                };
414	
415	            // Reset the liveness watchdog only on the market-data stream; recovery clears `down`.
416	            if matches!(role, PortRole::Mktdata | PortRole::Combined) {
417	                last_mkt = std::time::Instant::now();
418	                if down {
419	                    emit_status(&tx, &venue, "ok", 0);
420	                    down = false;
421	                }
422	            }
423	
424	            let ctx = FrameCtx {
425	                venue: &venue,
426	                tx: &tx,
427	                instruments: &instruments,
428	                kernel_rx_ts_ns: kernel_ns,
429	                recv_ts_ns: recv_ns,
430	                role,
431	                publisher,
432	            };
433	            processor.on_datagram(&channels[idx].buf[..n], &ctx);
434	        }
435	    }
436	}
437	
438	/// Map a feed's two-port (or combined single-port) layout to driver port roles. When the publisher
439	/// sends everything on one port (loopback demo), `mktdata == refdata`, so a single `Combined`
440	/// socket carries both halves.
441	fn two_port_roles(ports: FeedPorts) -> Vec<(PortRole, u16)> {
442	    let (mkt, refd) = (ports.mktdata(), ports.refdata());
443	    if mkt == refd {
444	        vec![(PortRole::Combined, mkt)]
445	    } else {
446	        vec![(PortRole::Mktdata, mkt), (PortRole::Refdata, refd)]
447	    }
448	}
449	
450	/// Run the receiver for one feed: pick the protocol's [`FrameProcessor`] and port roles from the
451	/// feed's [`FeedKind`], then drive the shared receive loop. Returns only on a fatal bind error
452	/// (it otherwise runs forever).
453	pub async fn run_feed(
454	    feed: Feed,
455	    iface: String,
456	    recv_buf: usize,
457	    tx: broadcast::Sender<FeedMessage>,
458	    instruments: InstrumentSnapshot,
459	    depth: DepthSnapshot,
460	) -> Result<()> {
461	    let venue = feed.venue.to_string();
462	    match feed.kind {
463	        FeedKind::TopOfBook => {
464	            let ports = two_port_roles(feed.ports);
465	            drive(
466	                feed.group,
467	                ports,
468	                iface,
469	                recv_buf,
470	                venue,
471	                tx,
472	                instruments,
473	                TobProcessor::new(feed.emit_trades),
474	            )
475	            .await
476	        }
477	        FeedKind::Midpoint => {
478	            let ports = two_port_roles(feed.ports);
479	            drive(
480	                feed.group,
481	                ports,
482	                iface,
483	                recv_buf,
484	                venue,
485	                tx,
486	                instruments,
487	                MidpointProcessor::new(),
488	            )
489	            .await
490	        }
491	        FeedKind::MarketByOrder => {
492	            let FeedPorts::ThreePort {
493	                mktdata,
494	                refdata,
495	                snapshot,
496	            } = feed.ports
497	            else {
498	                bail!("Market-by-Order feed '{venue}' must use FeedPorts::ThreePort (mktdata/refdata/snapshot)");
499	            };
500	            let ports = vec![
501	                (PortRole::Mktdata, mktdata),
502	                (PortRole::Refdata, refdata),
503	                (PortRole::Snapshot, snapshot),
504	            ];
505	            drive(
506	                feed.group,
507	                ports,
508	                iface,
509	                recv_buf,
510	                venue,
511	                tx,
512	                instruments,
513	                MboProcessor::new(depth, feed.emit_trades),
514	            )
515	            .await
516	        }
517	    }
518	}
519	
520	#[cfg(test)]
521	mod tests {
522	    use std::net::{IpAddr, Ipv4Addr, SocketAddr, SocketAddrV4};
523	
524	    use super::{datagram_src_ip, SeqCheck, SeqTracker, SockaddrStorage};
525	
526	    #[test]
527	    fn datagram_src_ip_extracts_v4() {
528	        let sa = SockaddrStorage::from(SocketAddr::V4(SocketAddrV4::new(
529	            Ipv4Addr::new(10, 0, 0, 5),
530	            1234,
531	        )));
532	        assert_eq!(
533	            datagram_src_ip(Some(sa)),
534	            IpAddr::V4(Ipv4Addr::new(10, 0, 0, 5))
535	        );
536	    }
537	
538	    #[test]
539	    fn datagram_src_ip_defaults_when_absent() {
540	        assert_eq!(datagram_src_ip(None), IpAddr::V4(Ipv4Addr::UNSPECIFIED));
541	    }
542	
543	    #[test]
544	    fn first_frame_on_a_channel() {
545	        let mut s = SeqTracker::default();
546	        assert_eq!(s.check(0, 0, 0), SeqCheck::First); // sequence starts at 0 per spec
547	    }
548	
549	    #[test]
550	    fn contiguous_sequence_is_ok() {
551	        let mut s = SeqTracker::default();
552	        assert_eq!(s.check(0, 0, 0), SeqCheck::First);
553	        assert_eq!(s.check(0, 0, 1), SeqCheck::Ok);
554	        assert_eq!(s.check(0, 0, 2), SeqCheck::Ok);
555	    }
556	
557	    #[test]
558	    fn forward_jump_is_accepted() {
559	        // The channel-0 sequence is global across groups, so a per-group jump is expected, not
560	        // loss: a forward jump is plain Ok (no gap accounting).
561	        let mut s = SeqTracker::default();
562	        assert_eq!(s.check(0, 0, 10), SeqCheck::First);
563	        assert_eq!(s.check(0, 0, 13), SeqCheck::Ok);
564	        assert_eq!(s.check(0, 0, 14), SeqCheck::Ok);
565	    }
566	
567	    #[test]
568	    fn lower_sequence_is_stale_and_anchor_holds() {
569	        let mut s = SeqTracker::default();
570	        assert_eq!(s.check(0, 0, 10), SeqCheck::First);
571	        assert_eq!(s.check(0, 0, 9), SeqCheck::Stale); // reordered/duplicated old datagram
572	        assert_eq!(s.check(0, 0, 3), SeqCheck::Stale);
573	        // The anchor stayed at 10 (stale frames don't advance it), so 11 is the next contiguous one.
574	        assert_eq!(s.check(0, 0, 11), SeqCheck::Ok);
575	    }
576	
577	    #[test]
578	    fn duplicate_of_last_is_not_stale() {
579	        // Equal sequence is a duplicate full-state update (idempotent); only strictly-lower is stale.
580	        let mut s = SeqTracker::default();
581	        assert_eq!(s.check(0, 0, 7), SeqCheck::First);
582	        assert_eq!(s.check(0, 0, 7), SeqCheck::Ok);
583	    }
584	
585	    #[test]
586	    fn reset_count_change_is_a_reset() {
587	        let mut s = SeqTracker::default();
588	        assert_eq!(s.check(0, 0, 100), SeqCheck::First);
589	        // Publisher reset the channel: reset_count bumped, sequence legitimately restarts at 0.
590	        // Without the reset_count check this 0 would be misread as a stale frame.
591	        assert_eq!(s.check(0, 1, 0), SeqCheck::Reset);
592	        assert_eq!(s.check(0, 1, 1), SeqCheck::Ok);
593	        // Within the new epoch, lower sequences are stale again.
594	        assert_eq!(s.check(0, 1, 0), SeqCheck::Stale);
595	    }
596	
597	    #[test]
598	    fn channels_are_tracked_independently() {
599	        let mut s = SeqTracker::default();
600	        assert_eq!(s.check(0, 0, 10), SeqCheck::First);
601	        assert_eq!(s.check(1, 0, 2), SeqCheck::First); // a different channel has its own counter
602	        assert_eq!(s.check(0, 0, 9), SeqCheck::Stale); // channel 0 still drops its own stale frame
603	        assert_eq!(s.check(1, 0, 3), SeqCheck::Ok);
604	    }
605	}
