//! doublezero-edge-connect - DoubleZero Edge multicast -> normalized WebSocket bridge.
//!
//! Binds each configured DZ Edge feed's multicast group, decodes the binary Top-of-Book
//! frames, and re-serves normalized quotes over a WebSocket that any trading engine can
//! subscribe to. One feed maps to one venue (see `ingest/feeds.rs`); the bridge ingests every
//! selected feed at once and consumers filter by venue over the WebSocket (PROTOCOL.md).
//! Run it on a host connected to DZ Edge (the `doublezero1` interface) so consumers never
//! have to bind multicast themselves.

use std::{
    collections::HashMap,
    sync::{Arc, Mutex},
};

use anyhow::{bail, Result};
use clap::Parser;
use tokio::{sync::broadcast, task::JoinSet};
use tracing::info;

use doublezero_edge_connect::{ingest, model, sinks};
use ingest::feeds;

#[derive(Parser, Debug)]
#[command(
    name = "doublezero-edge-connect",
    about = "DoubleZero Edge multicast -> WebSocket bridge"
)]
struct Args {
    /// Venue(s) to ingest, by name, repeatable (e.g. `--feed Hyperliquid`). Each name must
    /// be a known feed (see `feeds.rs`). Omit to ingest ALL known feeds.
    #[arg(long = "feed", env = "DZ_FEEDS", value_delimiter = ',')]
    feeds: Vec<String>,

    /// Interface to join the groups on - a name (e.g. "doublezero1") or an IPv4 address.
    /// Names are resolved to their IPv4 (as in edge-multicast-ref).
    #[arg(long, env = "DZ_IFACE", default_value = "doublezero1")]
    iface: String,

    /// Kernel socket receive buffer (SO_RCVBUF) in bytes, per feed socket.
    #[arg(long, env = "DZ_RECV_BUF", default_value_t = 8_388_608)]
    recv_buf: usize,

    /// WebSocket server bind address for consumers to connect to. The WS sink is on by default;
    /// pass an empty value (`--ws-bind ""`) to disable it.
    #[arg(long, env = "WS_BIND", default_value = "0.0.0.0:8081")]
    ws_bind: String,

    /// Server heartbeat (WS Ping) interval in seconds.
    #[arg(long, env = "WS_HEARTBEAT_SECS", default_value_t = 20)]
    ws_heartbeat_secs: u64,

    /// Close a client that sends no frame (incl. auto-Pong) for this many seconds.
    #[arg(long, env = "WS_IDLE_TIMEOUT_SECS", default_value_t = 60)]
    ws_idle_timeout_secs: u64,

    /// Max concurrent WebSocket clients; new connections beyond are rejected.
    #[arg(long, env = "WS_MAX_CLIENTS", default_value_t = 64)]
    ws_max_clients: usize,

    /// Max subscriptions per client.
    #[arg(long, env = "WS_MAX_SUBS", default_value_t = 256)]
    ws_max_subs: usize,

    /// Max inbound (control) messages per client per minute before disconnect.
    #[arg(long, env = "WS_MAX_INBOUND_PER_MIN", default_value_t = 600)]
    ws_max_inbound_per_min: u32,

    /// Broadcast buffer capacity (backpressure: a slow client drops the oldest beyond this).
    #[arg(long, env = "WS_BROADCAST_CAPACITY", default_value_t = 4096)]
    ws_broadcast_capacity: usize,
}

/// Resolve the `--feed` selection to a list of feeds: empty selection means all known feeds.
fn select_feeds(selection: &[String]) -> Result<Vec<&'static feeds::Feed>> {
    if selection.is_empty() {
        return Ok(feeds::FEEDS.iter().collect());
    }
    let mut chosen = Vec::new();
    for name in selection {
        let matches: Vec<&'static feeds::Feed> = feeds::FEEDS
            .iter()
            .filter(|f| f.venue.eq_ignore_ascii_case(name))
            .collect();
        if matches.is_empty() {
            let known: Vec<&str> = feeds::FEEDS.iter().map(|f| f.venue).collect();
            bail!("unknown feed '{name}'; known feeds: {}", known.join(", "));
        }
        chosen.extend(matches);
    }
    Ok(chosen)
}

#[tokio::main]
async fn main() -> Result<()> {
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::from_default_env().add_directive("info".parse()?),
        )
        .init();

    let args = Args::parse();
    info!(?args, "starting doublezero-edge-connect");

    let enabled = select_feeds(&args.feeds)?;
    info!(feeds = ?enabled.iter().map(|f| f.venue).collect::<Vec<_>>(), "ingesting feeds");

    let (tx, _rx) = broadcast::channel::<model::FeedMessage>(args.ws_broadcast_capacity);
    let instruments: model::InstrumentSnapshot = Arc::new(Mutex::new(HashMap::new()));
    let depth: model::DepthSnapshot = Arc::new(Mutex::new(HashMap::new()));

    // WebSocket sink: on by default; disable it by passing an empty `--ws-bind`.
    let ws = if args.ws_bind.is_empty() {
        info!("WebSocket sink disabled (empty --ws-bind)");
        None
    } else {
        let ws_cfg = sinks::ws::WsConfig {
            heartbeat: std::time::Duration::from_secs(args.ws_heartbeat_secs),
            idle_timeout: std::time::Duration::from_secs(args.ws_idle_timeout_secs),
            max_clients: args.ws_max_clients,
            max_subs: args.ws_max_subs,
            max_inbound_per_min: args.ws_max_inbound_per_min,
        };
        Some(tokio::spawn(sinks::ws::run(
            args.ws_bind.clone(),
            tx.clone(),
            instruments.clone(),
            depth.clone(),
            ws_cfg,
        )))
    };

    // One receiver task per feed; all publish onto the shared broadcast tagged with the
    // feed's venue, and the WS server fans them out to consumers (who filter by venue).
    let mut receivers = JoinSet::new();
    for feed in enabled {
        info!(venue = feed.venue, kind = ?feed.kind, group = %feed.group,
              mktdata_port = feed.ports.mktdata(), refdata_port = feed.ports.refdata(),
              snapshot_port = ?feed.ports.snapshot(), "starting feed receiver");
        receivers.spawn(ingest::receiver::run_feed(
            *feed,
            args.iface.clone(),
            args.recv_buf,
            tx.clone(),
            instruments.clone(),
            depth.clone(),
        ));
    }

    // Exit if the WS server (when enabled) or any feed receiver returns (they loop forever). When
    // the WS sink is disabled, that arm is a never-resolving future so the process is driven by the
    // receivers alone.
    tokio::select! {
        r = async { match ws {
            Some(handle) => handle.await,
            None => std::future::pending().await,
        } } => r??,
        Some(r) = receivers.join_next() => r??,
    }
    Ok(())
}

//! Normalized feed messages re-served over WebSocket to any trading engine.
//! Wire format is engine-agnostic JSON - see PROTOCOL.md.

use std::{
    collections::HashMap,
    sync::{Arc, Mutex},
};

use serde::{Deserialize, Serialize};

/// A normalized two-sided top-of-book update from any venue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NormalizedQuote {
    pub venue: String,
    pub symbol: String,
    pub bid: f64,
    pub ask: f64,
    pub bid_size: f64,
    pub ask_size: f64,
    /// Venue/source timestamp (nanoseconds since epoch), 0 if unknown.
    pub source_ts_ns: u64,
    /// When the bridge received it (user-space wall clock, nanoseconds since epoch).
    /// Taken *after* frame decode - kept for the kernel-vs-userspace jitter comparison.
    pub recv_ts_ns: u64,
    /// Kernel software RX timestamp from `SO_TIMESTAMPNS` (CLOCK_REALTIME nanoseconds),
    /// captured in the driver softirq *before* user-space. 0 when unavailable (e.g. the
    /// socket option is unsupported). This is the defendable wire-adjacent arrival time.
    #[serde(default)]
    pub kernel_rx_ts_ns: u64,
    /// Wall clock (nanoseconds since epoch) sampled by the WS server the instant before this
    /// quote is serialized and written to a subscriber. With `kernel_rx_ts_ns` / `recv_ts_ns`
    /// this decomposes the bridge's internal transit (kernel -> user-space -> WS hand-off).
    /// 0 until the WS server stamps it.
    #[serde(default)]
    pub ws_send_ts_ns: u64,
}

/// A normalized trade print (last sale) from any venue. Like [`NormalizedQuote`] it rides the
/// same four latency timestamps; unlike a quote it is a point-in-time event, not full state, so a
/// dropped trade is a missed print (not a stale book) and there is nothing to replay on connect.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NormalizedTrade {
    pub venue: String,
    pub symbol: String,
    pub price: f64,
    pub size: f64,
    /// `"buy"`, `"sell"`, or `"unknown"` - the aggressor (taker) side.
    pub aggressor_side: String,
    /// Venue-assigned trade identifier.
    pub trade_id: u64,
    /// Session cumulative traded volume reported by the venue (decimal), 0 if not provided.
    pub cumulative_volume: f64,
    /// Venue/source timestamp (nanoseconds since epoch), 0 if unknown.
    pub source_ts_ns: u64,
    /// When the bridge received it (user-space wall clock, ns since epoch), after frame decode.
    pub recv_ts_ns: u64,
    /// Kernel software RX timestamp from `SO_TIMESTAMPNS` (CLOCK_REALTIME ns), 0 when unavailable.
    #[serde(default)]
    pub kernel_rx_ts_ns: u64,
    /// Wall clock (ns since epoch) stamped by the WS server just before send; 0 until stamped.
    #[serde(default)]
    pub ws_send_ts_ns: u64,
}

/// A normalized derived mid price for an instrument (from the Midpoint sibling feed). Like a
/// quote it is full state per instrument (the latest mid), so it self-heals on the next message.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NormalizedMidpoint {
    pub venue: String,
    pub symbol: String,
    pub mid: f64,
    /// How the mid was computed (0 = the instrument's default method).
    pub method: u8,
    /// Quality bits: 0=stale, 1=one-sided, 2=crossed/locked, 3=synthetic.
    pub quality_flags: u8,
    /// Venue timestamp of the underlying book state (ns since epoch), 0 if unknown.
    pub book_ts_ns: u64,
    /// When the publisher computed the mid (ns since epoch), 0 if unknown.
    pub compute_ts_ns: u64,
    /// When the bridge received it (user-space wall clock, ns since epoch), after frame decode.
    pub recv_ts_ns: u64,
    /// Kernel software RX timestamp from `SO_TIMESTAMPNS` (CLOCK_REALTIME ns), 0 when unavailable.
    #[serde(default)]
    pub kernel_rx_ts_ns: u64,
    /// Wall clock (ns since epoch) stamped by the WS server just before send; 0 until stamped.
    #[serde(default)]
    pub ws_send_ts_ns: u64,
}

/// A normalized order-book depth snapshot, derived in the bridge from the Market-by-Order feed.
/// Each message is the **full** top-N of both sides (not a delta), so - like a quote - it
/// self-heals: a consumer that drops one under backpressure recovers on the next snapshot. Levels
/// are `[price, size]` decimal pairs, best first (bids high->low, asks low->high).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NormalizedDepth {
    pub venue: String,
    pub symbol: String,
    pub bids: Vec<[f64; 2]>,
    pub asks: Vec<[f64; 2]>,
    /// Timestamp of the latest applied book event (ns since epoch), 0 if unknown.
    pub source_ts_ns: u64,
    /// When the bridge produced this snapshot (user-space wall clock, ns since epoch).
    pub recv_ts_ns: u64,
    /// Kernel software RX timestamp from `SO_TIMESTAMPNS` (CLOCK_REALTIME ns), 0 when unavailable.
    #[serde(default)]
    pub kernel_rx_ts_ns: u64,
    /// Wall clock (ns since epoch) stamped by the WS server just before send; 0 until stamped.
    #[serde(default)]
    pub ws_send_ts_ns: u64,
}

/// A normalized instrument definition (so subscribers know precision/venue).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NormalizedInstrument {
    pub venue: String,
    pub symbol: String,
    pub price_exponent: i8,
    pub qty_exponent: i8,
}

/// A venue-level feed-health status (the PROTOCOL.md `status` candidate extension). Emitted when
/// the bridge's quote (mktdata) multicast for a venue goes silent past the idle watchdog, and
/// again when quotes recover - so consumers can gray out / restore that source. Carries no symbol
/// (it is about the whole venue feed); consumers ignoring unknown `type`s skip it harmlessly.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FeedStatus {
    pub venue: String,
    /// `"down"` when the quote feed has gone silent, `"ok"` once quotes flow again.
    pub state: String,
    /// Milliseconds the quote feed has been silent (0 when `state == "ok"`).
    pub stale_ms: u64,
    /// Wall clock (ns since epoch) this status was emitted.
    pub ts_ns: u64,
}

/// The tagged message envelope sent to WebSocket subscribers.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", rename_all = "snake_case")]
pub enum FeedMessage {
    Instrument(NormalizedInstrument),
    Quote(NormalizedQuote),
    Trade(NormalizedTrade),
    Midpoint(NormalizedMidpoint),
    Depth(NormalizedDepth),
    Status(FeedStatus),
}

impl FeedMessage {
    /// The (venue, symbol) this message is about - used for per-subscriber filtering. A `Status`
    /// is venue-level and carries no symbol, so it reports an empty symbol (the WS server matches
    /// it by venue alone - see `ws_server`).
    pub fn venue_symbol(&self) -> (&str, &str) {
        match self {
            FeedMessage::Instrument(i) => (i.venue.as_str(), i.symbol.as_str()),
            FeedMessage::Quote(q) => (q.venue.as_str(), q.symbol.as_str()),
            FeedMessage::Trade(t) => (t.venue.as_str(), t.symbol.as_str()),
            FeedMessage::Midpoint(m) => (m.venue.as_str(), m.symbol.as_str()),
            FeedMessage::Depth(d) => (d.venue.as_str(), d.symbol.as_str()),
            FeedMessage::Status(s) => (s.venue.as_str(), ""),
        }
    }
}

/// Latest known instrument definitions, keyed by `(venue, symbol)`, shared between the
/// receivers (which update it) and the WebSocket server (which replays it to each new
/// subscriber so reference data arrives before quotes - otherwise a client that connects
/// mid-stream sees a quote first and has to guess the price/qty precision).
///
/// The `(venue, symbol)` key disambiguates the same symbol across *different* venues (e.g.
/// `SOL-PERP` on Hyperliquid vs. Phoenix). It does NOT distinguish by protocol/feed: when one
/// venue is served by multiple feeds (e.g. Hyperliquid TOB + MBO), both write the same entry
/// (last-writer-wins). Those feeds are expected to agree on precision; `upsert_instrument` in
/// `processor.rs` warns if their exponents diverge.
pub type InstrumentSnapshot = Arc<Mutex<HashMap<(String, String), NormalizedInstrument>>>;

/// Latest order-book `depth` snapshot per `(venue, symbol)`, derived from the Market-by-Order feed
/// and shared with the WebSocket server so it can replay the current book to a newly-connecting
/// subscriber (depth is full state, so one replayed snapshot bootstraps the consumer immediately
/// instead of making it wait for the next periodic one). Updated by the MBO receiver.
pub type DepthSnapshot = Arc<Mutex<HashMap<(String, String), NormalizedDepth>>>;

/// Nanoseconds since the Unix epoch, for `recv_ts_ns`.
pub fn now_ns() -> u64 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos() as u64)
        .unwrap_or(0)
}

/// Monotonic nanoseconds from `CLOCK_MONOTONIC`. Unlike `std::time::Instant`, the raw
/// `clock_gettime` value is **comparable across processes on the same kernel**, so two
/// collectors (e.g. doublezero-edge-connect and hl-collector) can measure an inter-feed delta immune to
/// NTP steps/slew. Pair with `now_ns()` (wall clock) only to correlate with `source_ts`.
/// Provided for standalone collectors / null tests; not referenced by the bridge itself.
#[allow(dead_code)]
pub fn now_mono_ns() -> u64 {
    use nix::time::{clock_gettime, ClockId};
    clock_gettime(ClockId::CLOCK_MONOTONIC)
        .map(|ts| (ts.tv_sec() as u64) * 1_000_000_000 + ts.tv_nsec() as u64)
        .unwrap_or(0)
}

