1	//! Two-publisher integration test: feed the combined dual-publisher TOB fixture through
2	//! `TobProcessor` in capture order and assert the dedup contract holds across publishers. This is
3	//! the cross-publisher counterpart to `tob_single_publisher_contract` in `e2e.rs`: the fixture
4	//! carries two independent publishers mirroring the same Hyperliquid feed. Quotes dedup by a
5	//! per-(venue, symbol) `source_ts` latch-to-leader floor: within one `source_ts` tick only the
6	//! leader (first publisher to open it) is emitted — a slower publisher's samples at the same tick
7	//! arrive in a delay-corrupted order and are dropped — and a strictly-older BBO (stale laggard) plus
8	//! the leader's exact `(source_ts, content)` repeats are dropped too. So the emitted `source_ts` is
9	//! non-decreasing — not strictly increasing — per symbol, and within a tick the series is one
10	//! publisher's coherent subsequence.
11	
12	mod common;
13	
14	use common::assertions;
15	use doublezero_edge_connect::ingest::{
16	    codec,
17	    processor::TobProcessor,
18	    receiver::{FrameCtx, FrameProcessor, PortRole},
19	};
20	use serde_json::Value;
21	use std::{
22	    collections::HashMap,
23	    net::{IpAddr, Ipv4Addr},
24	    sync::{Arc, Mutex},
25	};
26	use tokio::sync::broadcast;
27	
28	/// Combined fixture record: `[u32 len LE][4B src_ip octets][1B role: 0=refdata,1=mktdata][frame]`.
29	fn read_combined(path: &str) -> Vec<(IpAddr, u8, Vec<u8>)> {
30	    let b = std::fs::read(path).unwrap();
31	    let mut out = Vec::new();
32	    let mut o = 0;
33	    while o < b.len() {
34	        let len = u32::from_le_bytes([b[o], b[o + 1], b[o + 2], b[o + 3]]) as usize;
35	        o += 4;
36	        let ip = IpAddr::V4(Ipv4Addr::new(b[o], b[o + 1], b[o + 2], b[o + 3]));
37	        o += 4;
38	        let role = b[o];
39	        o += 1;
40	        out.push((ip, role, b[o..o + len].to_vec()));
41	        o += len;
42	    }
43	    out
44	}
45	
46	/// Replay combined records through a single `TobProcessor` in capture order and collect the
47	/// emitted WS messages as JSON. This is the production demux+dedup path: each record's source IP
48	/// becomes `FrameCtx.publisher`, so the per-publisher SeqTracker and the cross-publisher dedup both
49	/// run exactly as in the binary.
50	fn replay(recs: &[(IpAddr, u8, Vec<u8>)]) -> Vec<Value> {
51	    let (tx, mut rx) = broadcast::channel(1 << 16);
52	    let instruments = Arc::new(Mutex::new(HashMap::new()));
53	    let mut p = TobProcessor::new(true);
54	    for (ip, role, frame) in recs {
55	        let ctx = FrameCtx {
56	            venue: "Hyperliquid",
57	            tx: &tx,
58	            instruments: &instruments,
59	            kernel_rx_ts_ns: 0,
60	            recv_ts_ns: 0,
61	            role: if *role == 0 {
62	                PortRole::Refdata
63	            } else {
64	                PortRole::Mktdata
65	            },
66	            publisher: *ip,
67	        };
68	        p.on_datagram(frame, &ctx);
69	    }
70	    let mut msgs = Vec::new();
71	    while let Ok(m) = rx.try_recv() {
72	        msgs.push(serde_json::to_value(&m).unwrap());
73	    }
74	    msgs
75	}
76	
77	/// Decode every refdata frame's instrument definitions into `instrument_id -> symbol`. Built from
78	/// all definitions in the fixture so per-symbol counts can be keyed by the human symbol.
79	fn symbol_by_id(recs: &[(IpAddr, u8, Vec<u8>)]) -> HashMap<u32, String> {
80	    let mut map = HashMap::new();
81	    for (_ip, _role, frame) in recs {
82	        if let Ok((_h, msgs)) = codec::decode_frame(frame) {
83	            for m in &msgs {
