183	/// non-decreasing assertion both fail (stale/out-of-order copies re-emit) and emitted == raw, so
184	/// this test pins the dedup, not just the fixture.
185	#[test]
186	fn per_symbol_dedup_is_independent() {
187	    let recs = read_combined("tests/fixtures/tob_multi_dual.combined.bin");
188	    let msgs = replay(&recs);
189	
190	    // (1) the dedup contract holds across the whole multi-symbol stream.
191	    assertions::no_business_duplicates(&msgs);
192	    assertions::quotes_well_formed(&msgs);
193	    // Staleness-floor non-decreasing monotonicity holds per (venue, symbol) across all symbols.
194	    assert_quote_source_ts_non_decreasing(&msgs);
