197	    let emitted = emitted_quotes_by_symbol(&msgs);
198	    // Each symbol emits the leader's distinct intra-tick changes: well below raw (non-leader samples,
199	    // stale laggard replays, and exact dups dropped) but well above a strict one-per-tick watermark.
200	    // The exact per-symbol counts aren't pinned here (the single-symbol test above pins BTC); this
201	    // test pins the cross-symbol *independence* property below.
202	
203	    // The fixture's three tiers (see PROVENANCE.md). Guard that the fixture still carries them so a
204	    // regenerated fixture that silently dropped a symbol fails loudly rather than vacuously passing.
205	    for sym in ["BTC", "SOL", "DOGE"] {
206	        let r = *raw.get(sym).unwrap_or(&0);
207	        let e = *emitted.get(sym).unwrap_or(&0);
208	        assert!(r > 0, "fixture carries no raw {sym} quotes");
209	        assert!(e > 0, "no {sym} quotes emitted");
210	        // (2) per-symbol dedup happened: two publishers mirror the feed, so emitted must drop below
211	        // raw for each symbol independently.
