216	    // by BTC volume" proves nothing.
217	    let (btc_raw, doge_raw) = (raw["BTC"], raw["DOGE"]);
218	    assert!(
219	        btc_raw > doge_raw * 5,
220	        "fixture volume spread too small: BTC raw {btc_raw} vs DOGE raw {doge_raw}"
221	    );
