224	    // restricted to DOGE) and confirm DOGE's emitted count is identical. DOGE has its own floor and
225	    // latched leader, so BTC/SOL traffic interleaved in the full run never advances or perturbs it;
226	    // the quiet symbol emits exactly the same set whether or not the busy symbols are present.
227	    let doge_id: u32 = *symbol_by_id(&recs)
228	        .iter()
229	        .find(|(_, s)| *s == "DOGE")
230	        .expect("DOGE definition in fixture")
