1	//! Semantic invariants over collected WS messages. These hold regardless of how many
2	//! publishers fed the input, so they double as the deduplication oracle.
3	
4	use std::collections::HashSet;
5	
6	use serde_json::Value;
7	
8	fn s<'a>(m: &'a Value, k: &str) -> &'a str {
9	    m.get(k).and_then(|v| v.as_str()).unwrap_or_default()
10	}
11	fn f(m: &Value, k: &str) -> f64 {
12	    m.get(k).and_then(|v| v.as_f64()).unwrap_or(0.0)
13	}
14	fn u(m: &Value, k: &str) -> u64 {
15	    m.get(k).and_then(|v| v.as_u64()).unwrap_or(0)
16	}
17	fn ty(m: &Value) -> &str {
18	    s(m, "type")
19	}
20	
21	/// Every quote/trade/depth references a symbol that was already declared by an
22	/// `instrument` message earlier in the stream (precision before price). The bridge
23	/// gates all price-carrying emissions on a known instrument definition, so trades
24	/// must also be preceded by their instrument.
25	pub fn instrument_before_price(msgs: &[Value]) {
26	    let mut known: HashSet<(String, String)> = HashSet::new();
27	    for m in msgs {
28	        let key = (s(m, "venue").to_string(), s(m, "symbol").to_string());
29	        match ty(m) {
30	            "instrument" => {
31	                known.insert(key);
32	            }
33	            "quote" | "trade" | "depth" => {
34	                assert!(
35	                    known.contains(&key),
36	                    "{} for {:?} arrived before its instrument definition",
37	                    ty(m),
38	                    key
39	                );
40	            }
41	            _ => {}
42	        }
43	    }
44	}
45	
46	/// No two messages carry identical business content.
47	///
48	/// **Key design — business-content only, BY DESIGN.** Per-receipt timestamps
49	/// (`recv_ts_ns`, `kernel_rx_ts_ns`, `ws_send_ts_ns`) are deliberately excluded.
50	/// Duplicate frames from competing publishers carry identical business fields but
51	/// different receipt timestamps; a business-content key collapses them so this
52	/// assertion catches missing dedup. Do NOT add `recv_ts_ns` to any key arm — that
53	/// gives each copy a distinct key and defeats the oracle.
54	///
55	/// **Quote arm:** `source_ts_ns` is venue-assigned content (identical across publishers
56	/// for the same update); the transport sequence number is NOT, which is why
57	/// content + source_ts is the right cross-publisher identity and a seqnum would not be.
58	///
59	/// **Trade arm:** `trade_id` is treated as globally unique for the run. A real
60	/// multi-publisher trade deduper will be WINDOWED (bounded memory) and can only collapse
61	/// copies within the window, so this oracle assumes window >= worst-case inter-publisher
62	/// lag.
63	///
64	/// **Depth arm:** identity is content-inclusive (venue + symbol + source_ts_ns + bids +
65	/// asks). Keying on source_ts_ns alone would false-fail when two publishers emit the
