72	/// quotes that both have `source_ts_ns == 0` (the "unknown" sentinel) and identical
73	/// bid/ask/sizes share the same key and produce a false-positive duplicate failure.
74	/// This does not occur in the current single-publisher fixtures. Future multi-publisher
75	/// dedup work must define duplicate identity precisely (e.g. by frame channel + sequence
76	/// number at ingest) rather than relying on this heuristic.
77	pub fn no_business_duplicates(msgs: &[Value]) {
78	    let mut seen: HashSet<String> = HashSet::new();
79	    for m in msgs {
80	        let key = match ty(m) {
81	            "quote" => format!(
82	                "q|{}|{}|{}|{}|{}|{}|{}",
83	                s(m, "venue"),
84	                s(m, "symbol"),
85	                u(m, "source_ts_ns"),
86	                f(m, "bid"),
87	                f(m, "ask"),
88	                f(m, "bid_size"),
89	                f(m, "ask_size")
90	            ),
91	            "trade" => format!(
92	                "t|{}|{}|{}",
93	                s(m, "venue"),
94	                s(m, "symbol"),
95	                u(m, "trade_id")
96	            ),
97	            // Depth identity is content-inclusive: venue + symbol + source_ts_ns + book state.
98	            // Two snapshots that share source_ts_ns but differ in bids/asks are not duplicates
99	            // (batch split or publisher divergence); two that match on all fields are.
100	            "depth" => format!(
101	                "d|{}|{}|{}|{}|{}",
102	                s(m, "venue"),
103	                s(m, "symbol"),
104	                u(m, "source_ts_ns"),
105	                m.get("bids").map(|v| v.to_string()).unwrap_or_default(),
106	                m.get("asks").map(|v| v.to_string()).unwrap_or_default(),
107	            ),
108	            _ => continue,
109	        };
110	        assert!(
111	            seen.insert(key.clone()),
112	            "duplicate business message: {key}"
113	        );
114	    }
