1	//! Replay golden `.bin` captures as loopback UDP multicast.
2	
3	/// Top-of-Book & Trades frame magic (ASCII "ZD" little-endian).
4	pub const TOB_MAGIC: u16 = 0x445A;
5	/// Market-by-Order frame magic.
6	pub const MBO_MAGIC: u16 = 0x4444;
7	
8	/// Split a captured `.bin` (length-prefixed packet log) into individual frame byte-slices.
9	///
10	/// The file format is a sequence of `[u32 LE length][frame bytes]` records, as produced
11	/// by the publisher's `encode_packets` function. The splitter walks by the 4-byte u32 LE
12	/// length prefix to find each frame boundary, then checks that the frame's first two bytes
13	/// match the expected protocol magic. Both checks double as fixture format validation.
14	///
15	/// The `assert!`/`assert_eq!` panics here are intentional — vendored goldens should fail
16	/// loud on corruption; switch to `Result` only if fixtures ever come from a less-trusted
17	/// generator.
18	pub fn split_frames(bytes: &[u8], magic: u16) -> Vec<Vec<u8>> {
19	    let mut frames = Vec::new();
20	    let mut off = 0usize;
21	    while off < bytes.len() {
22	        assert!(
23	            off + 4 <= bytes.len(),
24	            "fixture truncated: expected length prefix at offset {off}, only {} bytes remain",
25	            bytes.len() - off
26	        );
27	        let frame_len =
28	            u32::from_le_bytes([bytes[off], bytes[off + 1], bytes[off + 2], bytes[off + 3]])
29	                as usize;
30	        off += 4;
31	        assert!(
32	            frame_len >= 24 && off + frame_len <= bytes.len(),
33	            "frame at offset {}: bad frame_length {frame_len} (remaining {})",
34	            off - 4,
35	            bytes.len() - off
36	        );
37	        let got = u16::from_le_bytes([bytes[off], bytes[off + 1]]);
38	        assert_eq!(
39	            got,
40	            magic,
41	            "frame at offset {}: magic 0x{got:04X} != 0x{magic:04X}",
42	            off - 4
43	        );
44	        frames.push(bytes[off..off + frame_len].to_vec());
45	        off += frame_len;
46	    }
47	    frames
48	}
49	
50	use std::net::{Ipv4Addr, SocketAddrV4};
51	
52	use socket2::{Domain, Protocol, Socket, Type};
53	
54	/// The real Hyperliquid mainnet-beta multicast group. Multicast routing is by interface,
55	/// not address class. The bridge joins this group on INADDR_ANY (the default interface,
56	/// see `bridge.rs`), and the sender enables multicast loopback, so locally-sent datagrams
57	/// reach the bridge in the same container/CI network namespace WITHOUT depending on the
58	/// `lo` interface having the MULTICAST flag (it usually does not inside a container).
59	pub const HYPERLIQUID_GROUP: Ipv4Addr = Ipv4Addr::new(233, 84, 178, 15);
60	
61	/// Sender configured exactly like the HL publisher's own loopback E2E test (which runs in
62	/// their Linux CI): bound to UNSPECIFIED, multicast loopback on, TTL 1, and NO pinned
63	/// outgoing interface — let the kernel route the multicast and loop it back locally. Do
64	/// NOT `set_multicast_if_v4(LOCALHOST)`; pinning `lo` is the portability trap.
65	fn multicast_sender() -> std::io::Result<Socket> {
66	    let sock = Socket::new(Domain::IPV4, Type::DGRAM, Some(Protocol::UDP))?;
67	    sock.set_multicast_loop_v4(true)?;
68	    sock.set_multicast_ttl_v4(1)?;
69	    // TODO(#3): multi-source replay needs distinct src IPs + a re-sequenced fixture; all
70	    // datagrams here share one source IP, so independent-publisher MBO demux can't be
71	    // exercised yet.
72	    sock.bind(&SocketAddrV4::new(Ipv4Addr::UNSPECIFIED, 0).into())?;
73	    Ok(sock)
74	}
75	
76	/// Send each frame as one UDP datagram to `(group, port)`, with a tiny inter-packet gap so
77	/// the bridge's single-threaded decode keeps up.
78	pub fn send_frames(group: Ipv4Addr, port: u16, frames: &[Vec<u8>]) -> std::io::Result<()> {
79	    let sock = multicast_sender()?;
80	    let dst: socket2::SockAddr = SocketAddrV4::new(group, port).into();
81	    for f in frames {
82	        sock.send_to(f, &dst)?;
83	        std::thread::sleep(std::time::Duration::from_micros(200));
84	    }
85	    Ok(())
86	}
87

